"use client";

import {
  useEffect,
  useRef,
  useState,
  type PointerEvent as ReactPointerEvent,
} from "react";
import { SortableContext, verticalListSortingStrategy } from "@dnd-kit/sortable";
import {
  MaximizeIcon,
  PlusIcon,
  ZoomInIcon,
  ZoomOutIcon,
} from "@/lib/hugeicons";
import { useEditor, useEditorState, usePlayback, useProject } from "@mcut/react";
import {
  getProjectDurationMs,
  rangesOverlap,
  type ElementId,
} from "@mcut/timeline";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { Slider } from "@/components/ui/slider";
import { useActiveDrag } from "./editor-dnd";
import { PanelHeader } from "./editor-primitives";
import {
  MAX_PX_PER_MS,
  MIN_PX_PER_MS,
  useEditorUI,
} from "./editor-ui";
import { formatTimecode } from "./format";
import {
  ClipDragProvider,
  NEW_TRACK_LANE_HEIGHT,
  RULER_HEIGHT,
  TRACK_HEIGHT,
  useClipDragController,
} from "./timeline-drag";
import { MarkerLines, Playhead, Ruler, SnapGuide } from "./timeline-ruler";
import { DropGhostOverlay, HEADER_WIDTH, NewTrackLane, SortableRow } from "./timeline-tracks";

// ---------------------------------------------------------------------------
// Marquee selection
// ---------------------------------------------------------------------------

interface MarqueeState {
  x0: number;
  y0: number;
  x1: number;
  y1: number;
  active: boolean;
}

// ---------------------------------------------------------------------------
// Panel
// ---------------------------------------------------------------------------

export interface TimelinePanelProps {
  className?: string;
}

/**
 * Multi-track NLE timeline: magnetic clip move/trim with guide lines,
 * filmstrip/waveform clips, option-drag duplication to new tracks, dnd-kit
 * drop target lanes with ghost preview, marquee + shift multi-select,
 * sortable tracks, ⌘+wheel zoom at pointer.
 */
export function TimelinePanel({ className }: TimelinePanelProps) {
  const engine = useEditor();
  const project = useProject();
  const activeDrag = useActiveDrag();
  const clipDrag = useClipDragController();
  const { pxPerMs, setPxPerMs, zoomBy, timelineScrollRef } = useEditorUI();
  const durationMs = useEditorState((s) => getProjectDurationMs(s.project));
  const [marquee, setMarquee] = useState<MarqueeState | null>(null);
  const contentRef = useRef<HTMLDivElement | null>(null);

  // Quantized: while a drag grows the project, a raw width would change on
  // every frame and defeat the lanes' memoization.
  const contentWidth = Math.max(1600, Math.ceil(((durationMs + 15_000) * pxPerMs) / 400) * 400);
  const mediaDragActive = activeDrag !== null && activeDrag.kind !== "track";
  const rows = [...project.tracks].map((track, index) => ({ track, index })).reverse();
  const totalHeight = RULER_HEIGHT + NEW_TRACK_LANE_HEIGHT + rows.length * TRACK_HEIGHT;

  // ⌘/ctrl+wheel zoom anchored at the pointer (non-passive listener).
  useEffect(() => {
    const scroller = timelineScrollRef.current;
    if (!scroller) return;
    const onWheel = (event: WheelEvent) => {
      if (!event.ctrlKey && !event.metaKey) return;
      event.preventDefault();
      const rect = scroller.getBoundingClientRect();
      const anchorMs =
        (scroller.scrollLeft + (event.clientX - rect.left) - HEADER_WIDTH) / pxPerMs;
      zoomBy(event.deltaY < 0 ? 1.12 : 1 / 1.12, Math.max(0, anchorMs));
    };
    scroller.addEventListener("wheel", onWheel, { passive: false });
    return () => scroller.removeEventListener("wheel", onWheel);
  }, [pxPerMs, zoomBy, timelineScrollRef]);

  const fitToView = () => {
    const scroller = timelineScrollRef.current;
    if (!scroller || durationMs === 0) return;
    setPxPerMs((scroller.clientWidth - HEADER_WIDTH - 60) / durationMs);
    scroller.scrollLeft = 0;
  };

  // -- marquee ---------------------------------------------------------------

  const toContentPoint = (event: ReactPointerEvent) => {
    const rect = contentRef.current!.getBoundingClientRect();
    return { x: event.clientX - rect.left, y: event.clientY - rect.top };
  };

  const onBackgroundPointerDown = (event: ReactPointerEvent<HTMLDivElement>) => {
    const target = event.target as HTMLElement;
    if (!target.dataset.mcutLane) return; // clips/headers handle their own
    const point = toContentPoint(event);
    setMarquee({ x0: point.x, y0: point.y, x1: point.x, y1: point.y, active: false });
    event.currentTarget.setPointerCapture(event.pointerId);
  };

  const onBackgroundPointerMove = (event: ReactPointerEvent<HTMLDivElement>) => {
    if (!marquee) return;
    const point = toContentPoint(event);
    const next = { ...marquee, x1: point.x, y1: point.y };
    next.active =
      next.active || Math.hypot(next.x1 - next.x0, next.y1 - next.y0) > 5;
    setMarquee(next);
    if (!next.active) return;

    // Select clips intersecting the marquee (time × visual rows).
    const fromMs = (Math.min(next.x0, next.x1) - HEADER_WIDTH) / pxPerMs;
    const toMs = (Math.max(next.x0, next.x1) - HEADER_WIDTH) / pxPerMs;
    const rowsTop = RULER_HEIGHT + NEW_TRACK_LANE_HEIGHT;
    const rowTop = Math.floor((Math.min(next.y0, next.y1) - rowsTop) / TRACK_HEIGHT);
    const rowBottom = Math.floor((Math.max(next.y0, next.y1) - rowsTop) / TRACK_HEIGHT);
    const ids: ElementId[] = [];
    rows.forEach(({ track }, visualRow) => {
      if (visualRow < rowTop || visualRow > rowBottom) return;
      for (const element of track.elements) {
        if (rangesOverlap(fromMs, Math.max(1, toMs - fromMs), element.startMs, element.durationMs)) {
          ids.push(element.id);
        }
      }
    });
    engine.select(ids);
  };

  const onBackgroundPointerUp = (event: ReactPointerEvent<HTMLDivElement>) => {
    if (!marquee) return;
    if (!marquee.active) {
      // Plain click on empty lane: seek there and clear selection.
      engine.seek(Math.max(0, (marquee.x0 - HEADER_WIDTH) / pxPerMs));
      engine.clearSelection();
    }
    setMarquee(null);
    event.currentTarget.releasePointerCapture(event.pointerId);
  };

  const zoomSliderValue = Math.log(pxPerMs / MIN_PX_PER_MS) / Math.log(MAX_PX_PER_MS / MIN_PX_PER_MS);

  return (
    <ClipDragProvider value={clipDrag}>
    <div className={cn("flex flex-col", className)} data-mcut-timeline="">
      <PanelHeader>
        <Button
          variant="ghost"
          size="xs"
          title="Add track"
          onClick={() => engine.dispatch({ type: "addTrack" })}
        >
          <PlusIcon /> Track
        </Button>
        <div className="flex-1" />
        <Button variant="ghost" size="icon-xs" title="Fit timeline" onClick={fitToView}>
          <MaximizeIcon />
        </Button>
        <Button variant="ghost" size="icon-xs" title="Zoom out" onClick={() => zoomBy(1 / 1.4)}>
          <ZoomOutIcon />
        </Button>
        <Slider
          value={zoomSliderValue * 100}
          min={0}
          max={100}
          step={1}
          className="w-28! shrink-0"
          onValueChange={(value) => {
            const v = (Array.isArray(value) ? (value[0] ?? 0) : value) / 100;
            setPxPerMs(MIN_PX_PER_MS * Math.pow(MAX_PX_PER_MS / MIN_PX_PER_MS, v));
          }}
        />
        <Button variant="ghost" size="icon-xs" title="Zoom in" onClick={() => zoomBy(1.4)}>
          <ZoomInIcon />
        </Button>
      </PanelHeader>

      <div
        ref={timelineScrollRef}
        // isolate: the sticky ruler/gutter z-indexes (60/70) must not compete
        // with portaled popups (context menus are z-50 at the body level).
        className="relative isolate min-h-0 flex-1 overflow-auto overscroll-contain"
      >
        <div
          ref={contentRef}
          className="relative w-max min-w-full"
          style={{ minHeight: totalHeight }}
          onPointerDown={onBackgroundPointerDown}
          onPointerMove={onBackgroundPointerMove}
          onPointerUp={onBackgroundPointerUp}
        >
          {/* Ruler row */}
          <div className="sticky top-0 z-[60] flex">
            <div
              className="sticky left-0 z-[70] flex shrink-0 items-center justify-center border-r border-foreground/10 bg-card"
              style={{ width: HEADER_WIDTH, height: RULER_HEIGHT }}
            >
              <CurrentTime />
            </div>
            <Ruler pxPerMs={pxPerMs} contentWidth={contentWidth} />
          </div>

          <NewTrackLane contentWidth={contentWidth} dragActive={mediaDragActive} />

          <SortableContext
            items={rows.map(({ track }) => track.id)}
            strategy={verticalListSortingStrategy}
          >
            {rows.map(({ track }) => (
              <SortableRow
                key={track.id}
                track={track}
                pxPerMs={pxPerMs}
                contentWidth={contentWidth}
              />
            ))}
          </SortableContext>

          {durationMs === 0 && !activeDrag && (
            <div
              className="pointer-events-none absolute inset-x-0 top-1/2 z-0 flex justify-center text-xs text-muted-foreground"
              style={{ paddingLeft: HEADER_WIDTH }}
            >
              Drag media here, or press the import button in the media bin
            </div>
          )}

          {marquee?.active && (
            <div
              className="pointer-events-none absolute z-40 border border-primary bg-primary/10"
              style={{
                left: Math.min(marquee.x0, marquee.x1),
                top: Math.min(marquee.y0, marquee.y1),
                width: Math.abs(marquee.x1 - marquee.x0),
                height: Math.abs(marquee.y1 - marquee.y0),
              }}
            />
          )}

          <DropGhostOverlay rows={rows} pxPerMs={pxPerMs} />
          <MarkerLines pxPerMs={pxPerMs} height={totalHeight} />
          <SnapGuide pxPerMs={pxPerMs} height={totalHeight} />
          <Playhead pxPerMs={pxPerMs} height={totalHeight} />
        </div>
      </div>
    </div>
    </ClipDragProvider>
  );
}

function CurrentTime() {
  const currentTimeMs = usePlayback((s) => s.currentTimeMs);
  return (
    <span className="font-mono text-2xs text-primary tabular-nums">
      {formatTimecode(currentTimeMs)}
    </span>
  );
}

"use client";

import { useEffect, useRef, useState, type PointerEvent as ReactPointerEvent } from "react";
import { useEditor, useProject } from "@mcut/react";
import {
  animatableProperties,
  getEffectiveVolume,
  getKeyframes,
  hasKeyframes,
  type AnimatableProperty,
  type Project,
  type TimelineElement,
} from "@mcut/timeline";
import { cn } from "@/lib/utils";
import { useEditorUI } from "./editor-ui";
import { formatTimecode } from "./format";
import { collectSnapTargets, snapTime, type SnapTarget } from "./timeline-snap";

const SNAP_PX = 8;
export const KEYFRAME_DRAG_THRESHOLD_PX = 3;

/** Unique, sorted element-local keyframe times across every armed property. */
function aggregatedTimes(element: TimelineElement): number[] {
  const times = new Set<number>();
  for (const property of animatableProperties(element)) {
    for (const keyframe of getKeyframes(element, property)) times.add(keyframe.timeMs);
  }
  return [...times].sort((a, b) => a - b);
}

/** Animated properties that have a keyframe exactly at `timeMs`. */
export function keyframePropertiesAt(
  element: TimelineElement,
  timeMs: number,
): AnimatableProperty[] {
  return animatableProperties(element).filter((property) =>
    getKeyframes(element, property).some((keyframe) => keyframe.timeMs === timeMs),
  );
}

export function isKeyframeDragPastThreshold(startClientX: number, clientX: number): boolean {
  return Math.abs(clientX - startClientX) >= KEYFRAME_DRAG_THRESHOLD_PX;
}

export function isKeyframeSnapEnabled(snapEnabled: boolean, altKey: boolean): boolean {
  return snapEnabled && !altKey;
}

export function resolveKeyframeClickGesture({
  moved,
  startedAltKey,
  endedAltKey,
}: {
  moved: boolean;
  startedAltKey: boolean;
  endedAltKey: boolean;
}): "delete" | "seek" | "none" {
  if (moved) return "none";
  return startedAltKey || endedAltKey ? "delete" : "seek";
}

/**
 * Clamp a grouped keyframe move so every property in the group avoids its
 * neighboring keyframes. The moving key itself is identified by `originTimeMs`.
 */
export function clampKeyframeDragTarget(
  element: TimelineElement,
  properties: readonly AnimatableProperty[],
  originTimeMs: number,
  desiredTimeMs: number,
): number {
  let min = 0;
  let max = element.durationMs;
  for (const property of properties) {
    const track = getKeyframes(element, property);
    const previous = [...track].reverse().find((keyframe) => keyframe.timeMs < originTimeMs);
    const next = track.find((keyframe) => keyframe.timeMs > originTimeMs);
    if (previous) min = Math.max(min, previous.timeMs + 1);
    if (next) max = Math.min(max, next.timeMs - 1);
  }
  if (min > max) return originTimeMs;
  return Math.max(min, Math.min(max, Math.round(desiredTimeMs)));
}

export function canMoveKeyframeGroup(
  element: TimelineElement,
  properties: readonly AnimatableProperty[],
  fromTimeMs: number,
  toTimeMs: number,
): boolean {
  return properties.every((property) => {
    const track = getKeyframes(element, property);
    return (
      track.some((keyframe) => keyframe.timeMs === fromTimeMs) &&
      (toTimeMs === fromTimeMs || !track.some((keyframe) => keyframe.timeMs === toTimeMs))
    );
  });
}

function keyframeSnapTargets(
  project: Project,
  playheadMs: number,
  element: TimelineElement,
): SnapTarget[] {
  const selectedClipEdges: SnapTarget[] = [
    { timeMs: element.startMs, kind: "clip-start" },
    { timeMs: element.startMs + element.durationMs, kind: "clip-end" },
  ];
  return [
    ...collectSnapTargets(project, playheadMs, new Set([element.id])),
    ...selectedClipEdges,
  ].sort((a, b) => a.timeMs - b.timeMs);
}

function keyframeMarkerRows(element: TimelineElement): Array<{ timeMs: number; key: string }> {
  const signatureCounts = new Map<string, number>();
  return aggregatedTimes(element).map((timeMs) => {
    const signature = keyframePropertiesAt(element, timeMs).join("|");
    const ordinal = signatureCounts.get(signature) ?? 0;
    signatureCounts.set(signature, ordinal + 1);
    return { timeMs, key: `keyframe-${signature}-${ordinal}` };
  });
}

/**
 * CapCut-style keyframe diamonds on a selected clip. Drag retimes (snapping
 * to clip edges and the playhead), Option-drag bypasses snapping, click seeks
 * to the keyframe, and Option-click deletes it across all properties.
 */
export function KeyframeMarkers({
  element,
  pxPerMs,
}: {
  element: TimelineElement;
  pxPerMs: number;
}) {
  const engine = useEditor();
  const project = useProject();
  const { snapEnabled, setSnapGuideMs } = useEditorUI();
  const dragRef = useRef<{
    originTimeMs: number;
    currentTimeMs: number;
    startClientX: number;
    startedAltKey: boolean;
    moved: boolean;
    transactionStarted: boolean;
    properties: AnimatableProperty[];
  } | null>(null);
  const [dragBadge, setDragBadge] = useState<{
    timeMs: number;
    noSnap: boolean;
  } | null>(null);

  const removeAt = (timeMs: number) => {
    engine.transact(() => {
      for (const property of animatableProperties(element)) {
        if (getKeyframes(element, property).some((k) => k.timeMs === timeMs)) {
          try {
            engine.dispatch({ type: "removeKeyframe", elementId: element.id, property, timeMs });
          } catch {
            // Already gone.
          }
        }
      }
    });
  };

  const onPointerDown = (timeMs: number) => (event: ReactPointerEvent<HTMLButtonElement>) => {
    event.stopPropagation();
    const properties = keyframePropertiesAt(element, timeMs);
    if (properties.length === 0) return;
    dragRef.current = {
      originTimeMs: timeMs,
      currentTimeMs: timeMs,
      startClientX: event.clientX,
      startedAltKey: event.altKey,
      moved: false,
      transactionStarted: false,
      properties,
    };
    event.currentTarget.setPointerCapture(event.pointerId);
  };

  const onPointerMove = (event: ReactPointerEvent<HTMLButtonElement>) => {
    const drag = dragRef.current;
    if (!drag) return;
    const deltaPx = event.clientX - drag.startClientX;
    if (!drag.moved && !isKeyframeDragPastThreshold(drag.startClientX, event.clientX)) return;
    if (!drag.transactionStarted) {
      drag.transactionStarted = true;
      engine.beginTransaction();
    }
    drag.moved = true;

    const desiredLocal = drag.originTimeMs + deltaPx / pxPerMs;
    const live = engine.project.tracks.flatMap((t) => t.elements).find((e) => e.id === element.id);
    if (!live) return;
    const snapping = isKeyframeSnapEnabled(snapEnabled, event.altKey);
    const clampedDesired = clampKeyframeDragTarget(
      live,
      drag.properties,
      drag.originTimeMs,
      desiredLocal,
    );
    const snapped = snapTime(
      element.startMs + clampedDesired,
      keyframeSnapTargets(engine.project, engine.playback.state.currentTimeMs, element),
      SNAP_PX / pxPerMs,
      { enabled: snapping },
    );
    const toTimeMs = clampKeyframeDragTarget(
      live,
      drag.properties,
      drag.originTimeMs,
      snapped.ms - element.startMs,
    );

    setSnapGuideMs(snapping ? snapped.guideMs : null);
    setDragBadge({ timeMs: toTimeMs, noSnap: event.altKey });
    if (toTimeMs === drag.currentTimeMs) return;
    if (!canMoveKeyframeGroup(live, drag.properties, drag.currentTimeMs, toTimeMs)) return;

    for (const property of drag.properties) {
      try {
        engine.dispatch({
          type: "moveKeyframe",
          elementId: element.id,
          property,
          fromTimeMs: drag.currentTimeMs,
          toTimeMs,
        });
      } catch {
        return;
      }
    }
    drag.currentTimeMs = toTimeMs;
  };

  const finishPointer = (event: ReactPointerEvent<HTMLButtonElement>, cancelled = false) => {
    const drag = dragRef.current;
    if (!drag) return;
    dragRef.current = null;
    if (drag.transactionStarted) engine.endTransaction();
    setSnapGuideMs(null);
    setDragBadge(null);
    if (event.currentTarget.hasPointerCapture(event.pointerId)) {
      event.currentTarget.releasePointerCapture(event.pointerId);
    }
    if (cancelled) return;

    const gesture = resolveKeyframeClickGesture({
      moved: drag.moved,
      startedAltKey: drag.startedAltKey,
      endedAltKey: event.altKey,
    });
    if (gesture === "delete") removeAt(drag.originTimeMs);
    if (gesture === "seek") engine.seek(element.startMs + drag.originTimeMs);
  };

  void project; // markers re-render with project changes via parent

  return (
    <>
      {keyframeMarkerRows(element).map(({ timeMs, key }) => (
        <button
          key={key}
          type="button"
          className="absolute bottom-0 z-30 flex h-3.5 w-3 -translate-x-1/2 cursor-ew-resize items-center justify-center"
          style={{ left: timeMs * pxPerMs }}
          title="Keyframe - drag to retime, Option-drag no snap, Option-click delete"
          onPointerDown={onPointerDown(timeMs)}
          onPointerMove={onPointerMove}
          onPointerUp={(event) => finishPointer(event)}
          onPointerCancel={(event) => finishPointer(event, true)}
        >
          <span className="size-1.5 rotate-45 border border-overlay/60 bg-overlay-foreground shadow-sm" />
        </button>
      ))}
      {dragBadge && (
        <span
          className="pointer-events-none absolute bottom-4 z-40 flex -translate-x-1/2 items-center gap-1 rounded-sm bg-overlay/80 px-1.5 py-0.5 font-mono text-2xs text-overlay-foreground shadow-sm"
          style={{ left: dragBadge.timeMs * pxPerMs }}
        >
          {formatTimecode(element.startMs + dragBadge.timeMs)}
          {dragBadge.noSnap && <span className="font-sans text-2xs uppercase">No snap</span>}
        </span>
      )}
    </>
  );
}

/**
 * Premiere-style volume rubber band on audio clips: the line shows the
 * resolved volume curve; drag vertically to set volume (the nearest keyframe
 * when armed), ⌘/Ctrl-click to add a keyframe on the band.
 */
export function VolumeBand({
  element,
  widthPx,
  heightPx,
  interactive,
}: {
  element: TimelineElement & { type: "audio" | "video" };
  widthPx: number;
  heightPx: number;
  interactive: boolean;
}) {
  const engine = useEditor();
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const dragRef = useRef<{ targetTimeMs: number | null } | null>(null);
  const armed = hasKeyframes(element, "volume");

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const width = Math.max(1, Math.round(widthPx));
    const height = Math.max(1, Math.round(heightPx));
    canvas.width = width;
    canvas.height = height;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;
    ctx.strokeStyle = "rgba(103, 232, 249, 0.95)";
    ctx.lineWidth = 1.5;
    ctx.beginPath();
    for (let x = 0; x <= width; x += 3) {
      const timelineMs = element.startMs + (x / width) * element.durationMs;
      // Effective volume (keyframes × fades): the band shows what plays.
      const volume = Math.max(0, Math.min(2, getEffectiveVolume(element, timelineMs)));
      const y = height - (volume / 2) * height;
      if (x === 0) ctx.moveTo(x, y);
      else ctx.lineTo(x, y);
    }
    ctx.stroke();
  }, [element, widthPx, heightPx]);

  const valueFromY = (event: ReactPointerEvent<HTMLDivElement>): number => {
    const rect = event.currentTarget.getBoundingClientRect();
    const ratio = 1 - (event.clientY - rect.top) / rect.height;
    return Math.round(Math.max(0, Math.min(2, ratio * 2)) * 100) / 100;
  };

  const localTimeFromX = (event: ReactPointerEvent<HTMLDivElement>): number => {
    const rect = event.currentTarget.getBoundingClientRect();
    const ratio = (event.clientX - rect.left) / rect.width;
    return Math.max(0, Math.min(element.durationMs, Math.round(ratio * element.durationMs)));
  };

  const onPointerDown = (event: ReactPointerEvent<HTMLDivElement>) => {
    if (!interactive) return;
    event.stopPropagation();
    engine.beginTransaction();
    if (event.metaKey || event.ctrlKey) {
      // ⌘-click: add a keyframe on the band (arms the property).
      const timeMs = localTimeFromX(event);
      try {
        engine.dispatch({
          type: "setKeyframe",
          elementId: element.id,
          property: "volume",
          timeMs,
          value: valueFromY(event),
        });
      } catch {
        // Element vanished.
      }
      dragRef.current = { targetTimeMs: timeMs };
    } else if (armed) {
      // Drag the nearest keyframe's value (time stays put).
      const timeMs = localTimeFromX(event);
      const track = getKeyframes(element, "volume");
      const nearest = track.reduce((best, k) =>
        Math.abs(k.timeMs - timeMs) < Math.abs(best.timeMs - timeMs) ? k : best,
      );
      dragRef.current = { targetTimeMs: nearest.timeMs };
    } else {
      dragRef.current = { targetTimeMs: null }; // static volume drag
    }
    event.currentTarget.setPointerCapture(event.pointerId);
  };

  const onPointerMove = (event: ReactPointerEvent<HTMLDivElement>) => {
    const drag = dragRef.current;
    if (!drag) return;
    const value = valueFromY(event);
    try {
      if (drag.targetTimeMs === null) {
        engine.dispatch({ type: "updateElement", elementId: element.id, patch: { volume: value } });
      } else {
        engine.dispatch({
          type: "setKeyframe",
          elementId: element.id,
          property: "volume",
          timeMs: drag.targetTimeMs,
          value,
        });
      }
    } catch {
      // Ignore mid-drag races.
    }
  };

  const onPointerUp = (event: ReactPointerEvent<HTMLDivElement>) => {
    if (!dragRef.current) return;
    dragRef.current = null;
    engine.endTransaction();
    event.currentTarget.releasePointerCapture(event.pointerId);
  };

  return (
    <div
      className={cn(
        "absolute inset-0 z-20",
        interactive ? "cursor-ns-resize" : "pointer-events-none",
      )}
      title={
        interactive
          ? "Volume band — drag to set, ⌘-click to add a keyframe"
          : undefined
      }
      onPointerDown={onPointerDown}
      onPointerMove={onPointerMove}
      onPointerUp={onPointerUp}
      onPointerCancel={onPointerUp}
    >
      <canvas ref={canvasRef} className="pointer-events-none absolute inset-0 size-full" />
    </div>
  );
}

"use client";

import { useEffect, useLayoutEffect, useRef, useState } from "react";
import { extractAudioPeaks, getFilmstrip, type AudioPeaks, type Filmstrip } from "@mcut/media";
import { getSourceTimeMs, type AssetRef, type TimeMap } from "@mcut/timeline";
import { cn } from "@/lib/utils";

// Layout effect on the client so cached strips paint before the frame —
// remounting clips (e.g. a drag crossing lanes) must not flash a placeholder.
const useIsomorphicLayoutEffect = typeof window !== "undefined" ? useLayoutEffect : useEffect;

// Per-asset caches: decode once, redraw cheaply on zoom/trim changes. The
// resolved maps let remounts draw synchronously instead of waiting a
// microtask (which paints one placeholder frame per lane crossing).
const filmstripCache = new Map<string, Promise<Filmstrip | null>>();
const resolvedFilmstrips = new Map<string, Filmstrip | null>();
const peaksCache = new Map<string, Promise<AudioPeaks | null>>();
const resolvedPeaks = new Map<string, AudioPeaks | null>();

export function filmstripFor(asset: AssetRef): Promise<Filmstrip | null> {
  let cached = filmstripCache.get(asset.id);
  if (!cached) {
    const seconds = (asset.durationMs ?? 4000) / 1000;
    const frameCount = Math.max(8, Math.min(48, Math.ceil(seconds)));
    cached = getFilmstrip(asset.src, { frameCount, frameWidth: 96 })
      .then((strip) => {
        resolvedFilmstrips.set(asset.id, strip);
        return strip;
      })
      .catch(() => {
        // Transient decode failures (decoder pressure when many clips mount at
        // once) must not stick for the session — drop so a later render retries.
        filmstripCache.delete(asset.id);
        return null;
      });
    filmstripCache.set(asset.id, cached);
  }
  return cached;
}

export function peaksFor(asset: AssetRef): Promise<AudioPeaks | null> {
  let cached = peaksCache.get(asset.id);
  if (!cached) {
    const seconds = (asset.durationMs ?? 4000) / 1000;
    cached = extractAudioPeaks(asset.src, {
      buckets: Math.max(200, Math.min(4000, Math.round(seconds * 50))),
    })
      .then((peaks) => {
        resolvedPeaks.set(asset.id, peaks);
        return peaks;
      })
      .catch(() => {
        peaksCache.delete(asset.id);
        return null;
      });
    peaksCache.set(asset.id, cached);
  }
  return cached;
}

export function evictClipMediaCache(assetId: string): void {
  filmstripCache.delete(assetId);
  resolvedFilmstrips.delete(assetId);
  peaksCache.delete(assetId);
  resolvedPeaks.delete(assetId);
}

/**
 * Filmstrip background for video clips: tiles cached poster frames mapped to
 * the clip's trimmed source range, like CapCut/Premiere clip thumbnails.
 */
export function VideoFilmstrip({
  asset,
  widthPx,
  heightPx,
  trimStartMs,
  durationMs,
  timeMap,
  reversed,
  className,
}: {
  asset: AssetRef;
  widthPx: number;
  heightPx: number;
  trimStartMs: number;
  durationMs: number;
  timeMap?: TimeMap;
  reversed?: boolean;
  className?: string;
}) {
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const [ready, setReady] = useState(false);

  useIsomorphicLayoutEffect(() => {
    let cancelled = false;
    const draw = (strip: Filmstrip | null) => {
      if (cancelled || !strip) return;
      const canvas = canvasRef.current;
      if (!canvas) return;
      const width = Math.max(1, Math.round(widthPx));
      const height = Math.max(1, Math.round(heightPx));
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext("2d");
      if (!ctx) return;

      const assetDurationMs = asset.durationMs ?? Math.max(1, trimStartMs + durationMs);
      const tileWidth = Math.max(8, (strip.frameWidth / strip.frameHeight) * height);
      const clip = { startMs: 0, durationMs, trimStartMs, timeMap, reversed };
      for (let x = 0; x < width; x += tileWidth) {
        // Through the time remap, so sped/frozen clips show what actually plays.
        const sourceMs = getSourceTimeMs(clip, (x / width) * durationMs);
        const index = Math.max(
          0,
          Math.min(strip.frameCount - 1, Math.floor((sourceMs / assetDurationMs) * strip.frameCount)),
        );
        ctx.drawImage(
          strip.canvas,
          index * strip.frameWidth,
          0,
          strip.frameWidth,
          strip.frameHeight,
          x,
          0,
          tileWidth,
          height,
        );
      }
      setReady(true);
    };
    // Already decoded: paint before this frame so remounts (a drag crossing
    // lanes) never flash the placeholder.
    const resolved = resolvedFilmstrips.get(asset.id);
    if (resolved !== undefined) draw(resolved);
    else void filmstripFor(asset).then(draw);
    return () => {
      cancelled = true;
    };
  }, [asset, widthPx, heightPx, trimStartMs, durationMs, timeMap, reversed]);

  return (
    <canvas
      ref={canvasRef}
      className={cn(
        "pointer-events-none absolute inset-0 size-full",
        !ready && "animate-pulse bg-overlay-foreground/10",
        className,
      )}
    />
  );
}

/**
 * Mirrored waveform drawn from cached decoded peaks. Renders nothing when the
 * asset has no audio track. `variant="full"` fills the clip (audio clips);
 * `variant="strip"` hugs the bottom edge (audio texture over filmstrips).
 */
export function AudioWaveform({
  asset,
  widthPx,
  heightPx,
  trimStartMs,
  durationMs,
  timeMap,
  reversed,
  className,
  color = "rgba(255, 255, 255, 0.85)",
  variant = "full",
}: {
  asset: AssetRef;
  widthPx: number;
  heightPx: number;
  trimStartMs: number;
  durationMs: number;
  timeMap?: TimeMap;
  reversed?: boolean;
  className?: string;
  color?: string;
  variant?: "full" | "strip";
}) {
  const canvasRef = useRef<HTMLCanvasElement | null>(null);

  useIsomorphicLayoutEffect(() => {
    let cancelled = false;
    const draw = (result: AudioPeaks | null) => {
      if (cancelled || !result) return;
      const canvas = canvasRef.current;
      if (!canvas) return;
      const width = Math.max(1, Math.round(widthPx));
      const height = Math.max(1, Math.round(heightPx));
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext("2d");
      if (!ctx) return;

      const { peaks } = result;
      const assetDurationMs = asset.durationMs ?? result.durationMs;
      const mid = height / 2;
      ctx.fillStyle = color;
      const barWidth = 2;
      const gap = 1;
      const clip = { startMs: 0, durationMs, trimStartMs, timeMap, reversed };
      for (let x = 0; x < width; x += barWidth + gap) {
        const sourceMs = getSourceTimeMs(clip, (x / width) * durationMs);
        const bucket = Math.max(
          0,
          Math.min(peaks.length - 1, Math.floor((sourceMs / assetDurationMs) * peaks.length)),
        );
        const amplitude = Math.max(0.06, peaks[bucket] ?? 0);
        const barHeight = amplitude * (height - 4);
        ctx.fillRect(x, mid - barHeight / 2, barWidth, barHeight);
      }
    };
    const resolved = resolvedPeaks.get(asset.id);
    if (resolved !== undefined) draw(resolved);
    else void peaksFor(asset).then(draw);
    return () => {
      cancelled = true;
    };
  }, [asset, widthPx, heightPx, trimStartMs, durationMs, timeMap, reversed, color]);

  return (
    <canvas
      ref={canvasRef}
      className={cn(
        "pointer-events-none absolute",
        variant === "strip" ? "inset-x-0 bottom-0" : "inset-0 size-full",
        className,
      )}
      style={variant === "strip" ? { height: heightPx } : undefined}
    />
  );
}

"use client";

import { createContext, useContext, useRef, useState, type ReactNode } from "react";
import {
  closestCenter,
  DndContext,
  DragOverlay,
  PointerSensor,
  pointerWithin,
  useSensor,
  useSensors,
  type CollisionDetection,
  type DragEndEvent,
  type DragMoveEvent,
  type DragStartEvent,
} from "@dnd-kit/core";
import { FileVideoIcon, ImageIcon, MusicIcon, TypeIcon } from "@/lib/hugeicons";
import { useEditor, useProject } from "@mcut/react";
import {
  type AssetRef,
  type TrackId,
} from "@mcut/timeline";
import { useDropPreview, useEditorUI, type DropPreview } from "./editor-ui";
import {
  elementForAsset,
  elementForTextPreset,
  insertElementOnNewTrack,
  insertElementOnTrack,
  type TextPreset,
} from "./editor-actions";
import { collectSnapTargets, pointerToTimelineMs, snapClip, type SnapTarget } from "./timeline-snap";
import { formatDurationBadge } from "./format";

/** Payloads carried by dnd-kit drags. Track sorting is handled separately. */
export type EditorDragData =
  | { kind: "asset"; asset: AssetRef; thumb?: string }
  | { kind: "text-preset"; preset: TextPreset }
  | { kind: "track"; trackId: TrackId };

/** Data attached to timeline lane droppables. */
export interface LaneDropData {
  laneTrackId: string | "new-track";
}

const ActiveDragContext = createContext<EditorDragData | null>(null);

/** The payload currently being dragged (null when idle). */
export function useActiveDrag(): EditorDragData | null {
  return useContext(ActiveDragContext);
}

const SNAP_THRESHOLD_PX = 8;

function dragDurationMs(data: EditorDragData): number {
  if (data.kind === "asset") {
    return data.asset.kind === "image" ? 4000 : (data.asset.durationMs ?? 3000);
  }
  if (data.kind === "text-preset") return data.preset.durationMs;
  return 0;
}

function dragLabel(data: EditorDragData): string {
  if (data.kind === "asset") return data.asset.name ?? data.asset.kind;
  if (data.kind === "text-preset") return data.preset.name;
  return "";
}

function isLaneDropData(data: unknown): data is LaneDropData {
  return (
    typeof data === "object" &&
    data !== null &&
    "laneTrackId" in data &&
    typeof (data as LaneDropData).laneTrackId === "string"
  );
}

/** Lanes get pointer-precision; track sorting wants nearest-row. */
const collisionDetection: CollisionDetection = (args) => {
  const data = args.active.data.current as EditorDragData | undefined;
  if (data?.kind === "track") return closestCenter(args);
  const droppableContainers = args.droppableContainers.filter((container) => {
    const dropData = container.data.current;
    return isLaneDropData(dropData);
  });
  return pointerWithin({ ...args, droppableContainers });
};

function DragGhost({ data }: { data: EditorDragData }) {
  // Once the in-lane ghost is live, the floating card would only cover it —
  // the snapped ghost (with its own label/timecode) is the better feedback.
  const preview = useDropPreview();
  const Icon =
    data.kind === "text-preset"
      ? TypeIcon
      : data.kind === "asset" && data.asset.kind === "video"
        ? FileVideoIcon
        : data.kind === "asset" && data.asset.kind === "audio"
          ? MusicIcon
          : ImageIcon;
  const thumb = data.kind === "asset" ? data.thumb : undefined;
  if (preview) return null;
  return (
    <div className="pointer-events-none flex w-44 items-center gap-2 rounded-lg border bg-popover p-1.5 shadow-xl ring-1 ring-primary/40">
      <div className="flex size-9 shrink-0 items-center justify-center overflow-hidden rounded-md bg-muted">
        {thumb ? (
          // eslint-disable-next-line @next/next/no-img-element
          <img src={thumb} alt="" className="size-full object-cover" />
        ) : (
          <Icon className="size-4 text-muted-foreground" />
        )}
      </div>
      <div className="min-w-0 flex-1">
        <p className="truncate text-xs font-medium">{dragLabel(data)}</p>
        <p className="font-mono text-2xs text-muted-foreground">
          {formatDurationBadge(dragDurationMs(data))}
        </p>
      </div>
    </div>
  );
}

/**
 * One DndContext for the whole editor: media-bin assets and text presets
 * drag onto timeline lanes (with a snapped in-lane ghost), track rows sort
 * vertically. Clip move/trim stays on raw pointer events for ms precision.
 */
export function EditorDnd({
  children,
  onTrackSort,
}: {
  children: ReactNode;
  /** Called when a track row is dropped over another (sortable ids). */
  onTrackSort?: (activeTrackId: string, overTrackId: string) => void;
}) {
  const engine = useEditor();
  const project = useProject();
  const { pxPerMs, snapEnabled, editMode, setDropPreview, setSnapGuideMs } = useEditorUI();
  const [activeDrag, setActiveDrag] = useState<EditorDragData | null>(null);
  // Snap targets are stable for the whole drag (only the dragged payload
  // moves), so collect them once at drag start instead of per pointermove.
  const snapTargetsRef = useRef<SnapTarget[]>([]);
  // Coalesce drag moves to the frame rate: pointermove can fire at 120Hz+.
  const moveFrameRef = useRef<number | null>(null);
  const lastMoveRef = useRef<DragMoveEvent | null>(null);

  const sensors = useSensors(
    useSensor(PointerSensor, { activationConstraint: { distance: 6 } }),
  );

  const clear = () => {
    if (moveFrameRef.current !== null) {
      cancelAnimationFrame(moveFrameRef.current);
      moveFrameRef.current = null;
    }
    lastMoveRef.current = null;
    setActiveDrag(null);
    setDropPreview(null);
    setSnapGuideMs(null);
  };

  const previewFor = (event: DragMoveEvent): DropPreview | null => {
    const data = event.active.data.current as EditorDragData | undefined;
    if (!data || data.kind === "track") return null;
    const over = event.over;
    const laneData = over?.data.current as LaneDropData | undefined;
    if (!over || !laneData?.laneTrackId) return null;

    const activator = event.activatorEvent as PointerEvent;
    const pointerX = (activator.clientX ?? 0) + event.delta.x;
    const durationMs = dragDurationMs(data);
    const rawMs = pointerToTimelineMs(pointerX, over.rect, pxPerMs);
    const snapped = snapClip(rawMs, durationMs, snapTargetsRef.current, SNAP_THRESHOLD_PX / pxPerMs, {
      enabled: snapEnabled,
      fps: project.fps,
    });
    return {
      trackId: laneData.laneTrackId,
      startMs: Math.max(0, snapped.ms),
      durationMs,
      label: dragLabel(data),
    };
  };

  const handleDragStart = (event: DragStartEvent) => {
    snapTargetsRef.current = collectSnapTargets(project, engine.playback.state.currentTimeMs);
    setActiveDrag((event.active.data.current as EditorDragData) ?? null);
    setSnapGuideMs(null); // guide is implied by the ghost edges; keep UI quiet
  };

  const handleDragMove = (event: DragMoveEvent) => {
    const data = event.active.data.current as EditorDragData | undefined;
    if (!data || data.kind === "track") return;
    // Leading + trailing: apply the first move immediately, fold any burst
    // that follows into one update on the next frame.
    lastMoveRef.current = event;
    if (moveFrameRef.current !== null) return;
    setDropPreview(previewFor(event));
    moveFrameRef.current = requestAnimationFrame(() => {
      moveFrameRef.current = null;
      const last = lastMoveRef.current;
      if (last) setDropPreview(previewFor(last));
    });
  };

  const handleDragEnd = (event: DragEndEvent) => {
    const data = event.active.data.current as EditorDragData | undefined;
    try {
      if (data?.kind === "track") {
        const overId = event.over?.id;
        if (overId && overId !== event.active.id && onTrackSort) {
          onTrackSort(String(event.active.id), String(overId));
        }
        return;
      }
      const preview = previewFor(event);
      if (!data || !preview) return;
      const element =
        data.kind === "asset"
          ? elementForAsset(engine, data.asset)
          : elementForTextPreset(engine, data.preset);
      if (preview.trackId === "new-track") {
        insertElementOnNewTrack(engine, element, preview.startMs);
      } else {
        insertElementOnTrack(engine, preview.trackId as TrackId, element, preview.startMs, editMode);
      }
    } finally {
      clear();
    }
  };

  return (
    <DndContext
      id="mcut-editor-dnd"
      sensors={sensors}
      collisionDetection={collisionDetection}
      // Default measuring (once per drag) is enough: the "new track" lane is
      // always mounted, so rows never shift when a drag starts.
      onDragStart={handleDragStart}
      onDragMove={handleDragMove}
      onDragEnd={handleDragEnd}
      onDragCancel={clear}
    >
      <ActiveDragContext.Provider value={activeDrag}>
        {children}
        <DragOverlay dropAnimation={null}>
          {activeDrag && activeDrag.kind !== "track" ? <DragGhost data={activeDrag} /> : null}
        </DragOverlay>
      </ActiveDragContext.Provider>
    </DndContext>
  );
}

"use client";

import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useRef,
  useState,
  useSyncExternalStore,
  type ReactNode,
} from "react";
import type { PreviewQuality } from "@mcut/react";
import { clamp } from "./math";

/** A live drop ghost while dragging media over the timeline. */
export interface DropPreview {
  /** Target track id, or "new-track" for the phantom top lane. */
  trackId: string;
  startMs: number;
  durationMs: number;
  label: string;
}

// ---------------------------------------------------------------------------
// Drag overlay stores
// ---------------------------------------------------------------------------
// Drop ghost and snap guide update on every pointermove during a drag. They
// live in tiny external stores (not React context state) so a drag move
// re-renders only the overlay components that subscribe via useDropPreview/
// useSnapGuideMs — never the whole editor tree.

interface OverlayStore<T> {
  get: () => T;
  set: (value: T) => void;
  subscribe: (listener: () => void) => () => void;
}

function createOverlayStore<T>(initial: T, equals: (a: T, b: T) => boolean): OverlayStore<T> {
  let value = initial;
  const listeners = new Set<() => void>();
  return {
    get: () => value,
    set: (next: T) => {
      if (equals(value, next)) return;
      value = next;
      for (const listener of listeners) listener();
    },
    subscribe: (listener: () => void) => {
      listeners.add(listener);
      return () => listeners.delete(listener);
    },
  };
}

function dropPreviewEquals(a: DropPreview | null, b: DropPreview | null): boolean {
  if (a === b) return true;
  if (!a || !b) return false;
  return (
    a.trackId === b.trackId &&
    a.startMs === b.startMs &&
    a.durationMs === b.durationMs &&
    a.label === b.label
  );
}

interface DragOverlayStores {
  dropPreview: OverlayStore<DropPreview | null>;
  snapGuide: OverlayStore<number | null>;
}

const DragOverlayContext = createContext<DragOverlayStores | null>(null);

function useDragOverlayStores(): DragOverlayStores {
  const stores = useContext(DragOverlayContext);
  if (!stores) throw new Error("drag overlay hooks must be used inside <EditorUIProvider>");
  return stores;
}

/** The live drop ghost, or null when no media drag is over the timeline. */
export function useDropPreview(): DropPreview | null {
  const { dropPreview } = useDragOverlayStores();
  return useSyncExternalStore(dropPreview.subscribe, dropPreview.get, () => null);
}

/** The snap guide line (timeline ms), or null when nothing is snapping. */
export function useSnapGuideMs(): number | null {
  const { snapGuide } = useDragOverlayStores();
  return useSyncExternalStore(snapGuide.subscribe, snapGuide.get, () => null);
}

export type EditorTheme = "dark" | "light";

/**
 * Editing modes are VIEWS, not document state: they re-emphasize affordances
 * (multicam = layout bank + 1–9 switching) over the same project.
 */
export type EditorMode = "edit" | "multicam";

/**
 * Timeline pointer tools (Premiere's tool palette): select is the default
 * move/trim tool; ripple/roll change what the trim handles do; slip/slide
 * change what dragging the clip body does.
 */
export type TimelineTool = "select" | "ripple" | "roll" | "slip" | "slide";

/**
 * Placement mode for inserts and drops (Kdenlive's taxonomy): normal rejects
 * collisions, overwrite clears the landing range, insert ripples everything
 * after the point to the right.
 */
export type TimelineEditMode = "normal" | "overwrite" | "insert";

export interface EditorUIValue {
  /** Editor color theme (warm grey light/dark; tokens in globals.css). */
  theme: EditorTheme;
  setTheme: (value: EditorTheme) => void;
  /** Current editing mode (session-scoped; not persisted). */
  mode: EditorMode;
  setMode: (value: EditorMode) => void;
  /** Layout whose slots are being edited on the canvas (multicam mode). */
  editingLayoutId: string | null;
  setEditingLayoutId: (value: string | null) => void;
  /**
   * Slot edit state: index of the slot (within the editing layout) whose
   * properties the inspector shows. Shared so the canvas overlay and the
   * properties panel select and style the same slot.
   */
  editingSlotIndex: number | null;
  setEditingSlotIndex: (value: number | null) => void;
  /** Text element being edited INLINE on the canvas (double-click to enter). */
  editingTextId: string | null;
  setEditingTextId: (value: string | null) => void;
  /** Timeline zoom. */
  pxPerMs: number;
  setPxPerMs: (value: number) => void;
  /** Zoom keeping `anchorMs` under the same screen x (used by ⌘+wheel). */
  zoomBy: (factor: number, anchorMs?: number) => void;
  snapEnabled: boolean;
  setSnapEnabled: (value: boolean) => void;
  /** Active timeline pointer tool (session-scoped). */
  timelineTool: TimelineTool;
  setTimelineTool: (value: TimelineTool) => void;
  /** Placement mode for inserts/drops (session-scoped). */
  editMode: TimelineEditMode;
  setEditMode: (value: TimelineEditMode) => void;
  /** Drop a dissolve when a dragged clip is pushed flush against a neighbor. */
  autoCrossfade: boolean;
  setAutoCrossfade: (value: boolean) => void;
  /** Preview raster resolution ('auto' fits the pane; numbers cap the short side). */
  previewQuality: PreviewQuality;
  setPreviewQuality: (value: PreviewQuality) => void;
  /** Publish the drop ghost (read it via useDropPreview — it's not in this context). */
  setDropPreview: (value: DropPreview | null) => void;
  /** The timeline's horizontal scroll container (for zoom anchoring/auto-scroll). */
  timelineScrollRef: React.RefObject<HTMLDivElement | null>;
  /** Publish the snap guide line (read it via useSnapGuideMs). */
  setSnapGuideMs: (value: number | null) => void;
}

export const MIN_PX_PER_MS = 0.004;
export const MAX_PX_PER_MS = 0.6;
/** Left header gutter width inside the timeline, px. */
export const TIMELINE_HEADER_WIDTH = 288;

const EditorUIContext = createContext<EditorUIValue | null>(null);

const PREFS_KEY = "mcut:ui";

function loadPrefs(): {
  pxPerMs?: number;
  snapEnabled?: boolean;
  autoCrossfade?: boolean;
  theme?: EditorTheme;
  previewQuality?: PreviewQuality;
} {
  if (typeof window === "undefined") return {};
  try {
    return JSON.parse(window.localStorage.getItem(PREFS_KEY) ?? "{}");
  } catch {
    return {};
  }
}

function isPreviewQuality(value: unknown): value is PreviewQuality {
  return value === "auto" || value === "full" || (typeof value === "number" && value > 0);
}

export function EditorUIProvider({ children }: { children: ReactNode }) {
  const [pxPerMs, setPxPerMsState] = useState(0.05);
  const [snapEnabled, setSnapEnabledState] = useState(true);
  const [timelineTool, setTimelineTool] = useState<TimelineTool>("select");
  const [editMode, setEditMode] = useState<TimelineEditMode>("normal");
  const [autoCrossfade, setAutoCrossfadeState] = useState(false);
  const [previewQuality, setPreviewQualityState] = useState<PreviewQuality>("auto");
  const [theme, setThemeState] = useState<EditorTheme>("dark");
  const [mode, setModeState] = useState<EditorMode>("edit");
  const [editingLayoutId, setEditingLayoutIdState] = useState<string | null>(null);
  const [editingSlotIndex, setEditingSlotIndex] = useState<number | null>(null);
  const [editingTextId, setEditingTextId] = useState<string | null>(null);
  const setEditingLayoutId = useCallback((value: string | null) => {
    setEditingLayoutIdState(value);
    setEditingSlotIndex(null); // slot selection is scoped to one layout
  }, []);
  const setMode = useCallback((value: EditorMode) => {
    setModeState(value);
    // Leaving a mode always exits slot editing.
    setEditingLayoutIdState(null);
    setEditingSlotIndex(null);
    setEditingTextId(null);
  }, []);
  const [overlayStores] = useState<DragOverlayStores>(() => ({
    dropPreview: createOverlayStore<DropPreview | null>(null, dropPreviewEquals),
    snapGuide: createOverlayStore<number | null>(null, Object.is),
  }));
  const setDropPreview = useCallback(
    (value: DropPreview | null) => overlayStores.dropPreview.set(value),
    [overlayStores],
  );
  const setSnapGuideMs = useCallback(
    (value: number | null) => overlayStores.snapGuide.set(value),
    [overlayStores],
  );
  const timelineScrollRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    // Apply persisted prefs after hydration (a lazy initializer would make
    // the server and client first paints disagree).
    const timer = setTimeout(() => {
      const prefs = loadPrefs();
      if (prefs.pxPerMs) setPxPerMsState(clampZoom(prefs.pxPerMs));
      if (prefs.snapEnabled !== undefined) setSnapEnabledState(prefs.snapEnabled);
      if (prefs.autoCrossfade !== undefined) setAutoCrossfadeState(prefs.autoCrossfade);
      if (isPreviewQuality(prefs.previewQuality)) setPreviewQualityState(prefs.previewQuality);
      if (prefs.theme === "light" || prefs.theme === "dark") setThemeState(prefs.theme);
    }, 0);
    return () => clearTimeout(timer);
  }, []);

  const persist = (patch: Record<string, unknown>) => {
    try {
      window.localStorage.setItem(PREFS_KEY, JSON.stringify({ ...loadPrefs(), ...patch }));
    } catch {
      // Private mode: prefs just don't persist.
    }
  };

  const setPxPerMs = useCallback((value: number) => {
    const clamped = clampZoom(value);
    setPxPerMsState(clamped);
    persist({ pxPerMs: clamped });
  }, []);

  const setTheme = useCallback((value: EditorTheme) => {
    setThemeState(value);
    persist({ theme: value });
  }, []);

  const setSnapEnabled = useCallback((value: boolean) => {
    setSnapEnabledState(value);
    persist({ snapEnabled: value });
  }, []);

  const setAutoCrossfade = useCallback((value: boolean) => {
    setAutoCrossfadeState(value);
    persist({ autoCrossfade: value });
  }, []);

  const setPreviewQuality = useCallback((value: PreviewQuality) => {
    setPreviewQualityState(value);
    persist({ previewQuality: value });
  }, []);

  const zoomBy = useCallback(
    (factor: number, anchorMs?: number) => {
      setPxPerMsState((previous) => {
        const next = clampZoom(previous * factor);
        const scroller = timelineScrollRef.current;
        if (scroller && anchorMs !== undefined) {
          // Keep anchorMs under the same screen x after the zoom.
          const anchorX = anchorMs * previous - scroller.scrollLeft;
          requestAnimationFrame(() => {
            scroller.scrollLeft = anchorMs * next - anchorX;
          });
        }
        persist({ pxPerMs: next });
        return next;
      });
    },
    [],
  );

  // Memoized so a provider re-render doesn't re-render every consumer; only
  // actual value changes do.
  const value = useMemo<EditorUIValue>(
    () => ({
      theme,
      setTheme,
      mode,
      setMode,
      editingLayoutId,
      setEditingLayoutId,
      editingSlotIndex,
      setEditingSlotIndex,
      editingTextId,
      setEditingTextId,
      pxPerMs,
      setPxPerMs,
      zoomBy,
      snapEnabled,
      setSnapEnabled,
      timelineTool,
      setTimelineTool,
      editMode,
      setEditMode,
      autoCrossfade,
      setAutoCrossfade,
      previewQuality,
      setPreviewQuality,
      setDropPreview,
      timelineScrollRef,
      setSnapGuideMs,
    }),
    [
      theme,
      setTheme,
      mode,
      setMode,
      editingLayoutId,
      setEditingLayoutId,
      editingSlotIndex,
      editingTextId,
      pxPerMs,
      setPxPerMs,
      zoomBy,
      snapEnabled,
      setSnapEnabled,
      timelineTool,
      editMode,
      autoCrossfade,
      setAutoCrossfade,
      previewQuality,
      setPreviewQuality,
      setDropPreview,
      setSnapGuideMs,
    ],
  );

  return (
    <EditorUIContext.Provider value={value}>
      <DragOverlayContext.Provider value={overlayStores}>
        {children}
      </DragOverlayContext.Provider>
    </EditorUIContext.Provider>
  );
}

function clampZoom(value: number): number {
  return clamp(value, MIN_PX_PER_MS, MAX_PX_PER_MS);
}

export function useEditorUI(): EditorUIValue {
  const context = useContext(EditorUIContext);
  if (!context) throw new Error("useEditorUI must be used inside <EditorUIProvider>");
  return context;
}

import {
  collectSnapTargets as collectTimelineSnapTargets,
  type Project,
  type SnapTarget,
} from "@mcut/timeline";

// The snap engine itself (targets, nearest-target search, frame fallback)
// lives in @mcut/timeline so every gesture and any host app agree on policy;
// this module keeps the app-shaped entry points.
export { snapClip, snapTime } from "@mcut/timeline";
export type { SnapClipResult, SnapOptions, SnapResult, SnapTarget } from "@mcut/timeline";

/**
 * Magnetic snap targets: timeline zero, the playhead, markers, and every
 * clip edge (except the elements being dragged). Sorted by time.
 */
export function collectSnapTargets(
  project: Project,
  playheadMs: number,
  excludeElementIds: ReadonlySet<string> = new Set(),
): SnapTarget[] {
  return collectTimelineSnapTargets(project, { playheadMs, excludeElementIds });
}

/** Convert a pointer clientX into timeline ms for a lane element. */
export function pointerToTimelineMs(
  clientX: number,
  laneRect: { left: number },
  pxPerMs: number,
): number {
  return Math.max(0, Math.round((clientX - laneRect.left) / pxPerMs));
}

"use client";

import { createContext, useContext, useEffect, useRef, useState } from "react";
import { useEditor } from "@mcut/react";
import {
  canPlaceIgnoring,
  collectClipDragBases,
  computeSlipRange,
  planAutoCrossfade,
  planDuplicateClipsToNewTracks,
  resolveToolMode,
  type ClipDragBase,
  type ClipDragMode,
} from "@mcut/editor";
import {
  createTrackId,
  getElementLocation,
  MIN_ELEMENT_DURATION_MS,
  type ElementId,
  type Track,
} from "@mcut/timeline";
import { TIMELINE_HEADER_WIDTH, useEditorUI } from "./editor-ui";
import { collectSnapTargets, snapClip, snapTime, type SnapTarget } from "./timeline-snap";

type Engine = ReturnType<typeof useEditor>;

export type { ClipDragMode } from "@mcut/editor";

// Timeline geometry shared between the panel (layout) and the drag
// controller (row math, auto-scroll edges).
export const TRACK_HEIGHT = 56;
export const RULER_HEIGHT = 28;
/** Height of the always-mounted "new track" drop lane above the rows. */
export const NEW_TRACK_LANE_HEIGHT = 36;
export const SNAP_PX = 8;

/** Pointer travel before a press becomes a drag (vs a click/select). */
const DRAG_THRESHOLD_PX = 4;
/** Width of the auto-scroll zones at the scroller edges. */
const AUTO_SCROLL_EDGE_PX = 36;
/** Auto-scroll speed cap, px per frame. */
const AUTO_SCROLL_MAX_PX = 18;

export interface ClipDragBeginOptions {
  mode: ClipDragMode;
  /** Every element in the gesture, anchor (grabbed clip) first. */
  ids: ElementId[];
  /** ⌥-drag: copy the clips onto new tracks and move the copies. */
  duplicateOnDrag: boolean;
}

export interface ClipDragDeps {
  engine: Engine;
  pxPerMs: number;
  snapEnabled: boolean;
  /** Drop a dissolve when a move shoves a clip flush against a neighbor. */
  autoCrossfade: boolean;
  setSnapGuideMs: (ms: number | null) => void;
  scrollerRef: React.RefObject<HTMLElement | null>;
}

interface ClipDragGesture {
  mode: ClipDragMode;
  pointerId: number;
  ids: ElementId[];
  bases: Map<ElementId, ClipDragBase>;
  startClientX: number;
  startClientY: number;
  startScrollLeft: number;
  startScrollTop: number;
  lastClientX: number;
  lastClientY: number;
  lastAltKey: boolean;
  /** Pointer travelled past the threshold; a transaction is open. */
  active: boolean;
  duplicateOnDrag: boolean;
  duplicated: boolean;
  createdTrackIds: Track["id"][];
  /** The dragged element ids (excluded from snapping/collision). */
  ignore: ReadonlySet<string>;
  /** Snap targets, collected once at activation — only the gesture's own clips move. */
  targets: SnapTarget[];
  /** Delta already dispatched for delta-based modes (slip/slide/roll/ripple). */
  appliedDeltaMs: number;
  /** roll-start rolls the PREVIOUS clip's end cut; resolved at begin(). */
  rollTargetId: ElementId | null;
  /** Slip clamp across the gesture's members, computed at begin(). */
  slipRange: { minMs: number; maxMs: number } | null;
}

function duplicateClipsToNewTracks(
  engine: Engine,
  ids: readonly ElementId[],
): { ids: ElementId[]; bases: Map<ElementId, ClipDragBase>; createdTrackIds: Track["id"][] } | null {
  const plan = planDuplicateClipsToNewTracks(engine.project, ids);
  if (!plan) return null;
  for (const command of plan.commands) {
    engine.dispatch(command);
  }
  return {
    ids: plan.ids,
    bases: collectClipDragBases(engine.project, plan.ids),
    createdTrackIds: plan.createdTrackIds,
  };
}

function removeEmptyCreatedTracks(engine: Engine, trackIds: readonly Track["id"][]) {
  for (const trackId of trackIds) {
    const track = engine.project.tracks.find((t) => t.id === trackId);
    if (track && track.elements.length === 0) {
      engine.dispatch({ type: "removeTrack", trackId });
    }
  }
}

/** Scroll velocity toward whichever edge zone `pos` is inside, else 0. */
function edgeScrollSpeed(pos: number, min: number, max: number): number {
  if (pos < min + AUTO_SCROLL_EDGE_PX) {
    return -Math.min(AUTO_SCROLL_MAX_PX, ((min + AUTO_SCROLL_EDGE_PX - pos) / AUTO_SCROLL_EDGE_PX) * AUTO_SCROLL_MAX_PX);
  }
  if (pos > max - AUTO_SCROLL_EDGE_PX) {
    return Math.min(AUTO_SCROLL_MAX_PX, ((pos - (max - AUTO_SCROLL_EDGE_PX)) / AUTO_SCROLL_EDGE_PX) * AUTO_SCROLL_MAX_PX);
  }
  return 0;
}

/**
 * One drag gesture controller per timeline, owning clip move/trim from
 * pointerdown to commit.
 *
 * The listeners live on `window` and all state lives here — never on the
 * clip's DOM node. A cross-track move remounts the clip under another lane,
 * which destroys its node and would silently kill a node-bound gesture
 * (and strand the open transaction). With the controller, the clip is just
 * the place the gesture starts.
 *
 * Gesture model (matching desktop NLEs):
 * - press is a click until the pointer travels {@link DRAG_THRESHOLD_PX};
 *   only then does a transaction open (one undo entry per gesture)
 * - live dispatch, coalesced to the frame rate: the project is the preview
 * - Escape/blur/pointercancel aborts and rolls back via cancelTransaction
 * - a release we never see (outside the window) commits at the last applied
 *   position: pointer capture on the scroller catches most of these, and a
 *   buttons check on pointermove ends anything that slips through
 * - pointer near the scroller edges auto-scrolls, and the scroll delta is
 *   folded into the time/row math so the clip tracks the pointer
 */
export class ClipDragController {
  /** Deps live behind a ref refreshed each render; always read at event time. */
  constructor(private readonly depsRef: { readonly current: ClipDragDeps | null }) {}

  private get deps(): ClipDragDeps {
    const deps = this.depsRef.current;
    if (!deps) throw new Error("ClipDragController used before its deps were attached");
    return deps;
  }

  private gesture: ClipDragGesture | null = null;
  private autoScrollFrame: number | null = null;
  private updateFrame: number | null = null;
  /** A move arrived while a frame was pending; run one trailing update. */
  private pendingMove = false;
  private previousBodyUserSelect: string | null = null;
  private capture: { element: Element; pointerId: number } | null = null;

  begin(
    event: { clientX: number; clientY: number; pointerId: number },
    options: ClipDragBeginOptions,
  ): void {
    this.cancel(); // a stray previous gesture must not leak its transaction
    const project = this.deps.engine.project;
    const bases = collectClipDragBases(project, options.ids);
    if (options.ids.length === 0 || !bases.has(options.ids[0]!)) return;
    // Tool gestures degrade to their plain counterparts when their structural
    // requirements (adjacent neighbors, slippable source) aren't met.
    const resolved = resolveToolMode(project, options.mode, options.ids);
    const scroller = this.deps.scrollerRef.current;
    this.gesture = {
      mode: resolved.mode,
      pointerId: event.pointerId,
      ids: options.ids,
      bases,
      startClientX: event.clientX,
      startClientY: event.clientY,
      startScrollLeft: scroller?.scrollLeft ?? 0,
      startScrollTop: scroller?.scrollTop ?? 0,
      lastClientX: event.clientX,
      lastClientY: event.clientY,
      lastAltKey: options.duplicateOnDrag,
      active: false,
      duplicateOnDrag: options.duplicateOnDrag,
      duplicated: false,
      createdTrackIds: [],
      ignore: new Set<string>(options.ids),
      targets: [],
      appliedDeltaMs: 0,
      rollTargetId: resolved.rollTargetId,
      slipRange: resolved.mode === "slip" ? computeSlipRange(project, options.ids) : null,
    };
    this.attach();
  }

  /** True while a gesture is past the drag threshold. */
  get dragging(): boolean {
    return this.gesture?.active ?? false;
  }

  dispose(): void {
    this.cancel();
  }

  // -- listeners --------------------------------------------------------------

  private onPointerMove = (event: PointerEvent) => {
    const gesture = this.gesture;
    if (!gesture || event.pointerId !== gesture.pointerId) return;
    if ((event.buttons & 1) === 0) {
      // The press was released where no pointerup reached us (outside the
      // window, capture lost): commit at the last applied position instead
      // of letting the clip chase a button-up pointer.
      this.finish();
      return;
    }
    gesture.lastClientX = event.clientX;
    gesture.lastClientY = event.clientY;
    gesture.lastAltKey = event.altKey;
    if (!gesture.active) {
      const travelled = Math.hypot(
        event.clientX - gesture.startClientX,
        event.clientY - gesture.startClientY,
      );
      // Body gestures (move/slip/slide) keep the click-vs-drag threshold;
      // edge gestures react immediately.
      const bodyGesture =
        gesture.mode === "move" || gesture.mode === "slip" || gesture.mode === "slide";
      const threshold = bodyGesture ? DRAG_THRESHOLD_PX : 1;
      if (travelled < threshold) return;
      this.activate();
    }
    this.scheduleUpdate();
  };

  /**
   * Coalesce moves to the frame rate (pointermove fires at 120Hz+ on
   * ProMotion): the first move of a burst applies immediately, the rest fold
   * into one trailing update on the next frame.
   */
  private scheduleUpdate(): void {
    if (this.updateFrame !== null) {
      this.pendingMove = true;
      return;
    }
    this.update();
    this.updateFrame = requestAnimationFrame(() => {
      this.updateFrame = null;
      if (this.pendingMove) {
        this.pendingMove = false;
        this.update();
      }
    });
  }

  private onPointerUp = (event: PointerEvent) => {
    const gesture = this.gesture;
    if (!gesture || event.pointerId !== gesture.pointerId) return;
    this.finish();
  };

  private onPointerCancel = (event: PointerEvent) => {
    const gesture = this.gesture;
    if (!gesture || event.pointerId !== gesture.pointerId) return;
    this.cancel();
  };

  private onKeyDown = (event: KeyboardEvent) => {
    if (event.key !== "Escape" || !this.gesture) return;
    event.preventDefault();
    event.stopPropagation();
    this.cancel();
  };

  private onWindowBlur = () => {
    this.cancel();
  };

  private attach(): void {
    window.addEventListener("pointermove", this.onPointerMove);
    window.addEventListener("pointerup", this.onPointerUp);
    window.addEventListener("pointercancel", this.onPointerCancel);
    window.addEventListener("keydown", this.onKeyDown, true);
    window.addEventListener("blur", this.onWindowBlur);
  }

  private detach(): void {
    window.removeEventListener("pointermove", this.onPointerMove);
    window.removeEventListener("pointerup", this.onPointerUp);
    window.removeEventListener("pointercancel", this.onPointerCancel);
    window.removeEventListener("keydown", this.onKeyDown, true);
    window.removeEventListener("blur", this.onWindowBlur);
    if (this.capture !== null) {
      try {
        this.capture.element.releasePointerCapture(this.capture.pointerId);
      } catch {
        // Pointer already released the capture itself.
      }
      this.capture = null;
    }
    if (this.autoScrollFrame !== null) {
      cancelAnimationFrame(this.autoScrollFrame);
      this.autoScrollFrame = null;
    }
    if (this.updateFrame !== null) {
      cancelAnimationFrame(this.updateFrame);
      this.updateFrame = null;
    }
    this.pendingMove = false;
    if (this.previousBodyUserSelect !== null) {
      document.body.style.userSelect = this.previousBodyUserSelect;
      this.previousBodyUserSelect = null;
    }
  }

  // -- gesture lifecycle ------------------------------------------------------

  private activate(): void {
    const gesture = this.gesture!;
    gesture.active = true;
    this.deps.engine.beginTransaction();
    // Capture on a stable node (never the clip, which remounts mid-drag) so
    // pointerup still reaches us when the button is released outside the
    // window. Also overrides touch's implicit capture on the clip node.
    const captureElement = this.deps.scrollerRef.current ?? document.body;
    try {
      captureElement.setPointerCapture(gesture.pointerId);
      this.capture = { element: captureElement, pointerId: gesture.pointerId };
    } catch {
      this.capture = null; // pointer already gone; the buttons guard covers us
    }
    this.previousBodyUserSelect = document.body.style.userSelect;
    document.body.style.userSelect = "none";
    if (gesture.duplicateOnDrag && !gesture.duplicated) {
      const duplicated = duplicateClipsToNewTracks(this.deps.engine, gesture.ids);
      if (duplicated) {
        gesture.ids = duplicated.ids;
        gesture.bases = duplicated.bases;
        gesture.createdTrackIds = duplicated.createdTrackIds;
        gesture.duplicated = true;
        this.deps.engine.select(duplicated.ids);
        gesture.ignore = new Set<string>(gesture.ids);
      }
    }
    // Everything else stands still during the gesture, so snap targets are
    // collected once here instead of on every pointermove.
    gesture.targets = collectSnapTargets(
      this.deps.engine.project,
      this.deps.engine.playback.state.currentTimeMs,
      gesture.ignore,
    );
    this.startAutoScroll();
  }

  private finish(): void {
    const gesture = this.gesture;
    if (!gesture) return;
    if (gesture.active && this.pendingMove) {
      // Apply the coalesced final move before committing the transaction.
      this.pendingMove = false;
      this.update();
    }
    this.gesture = null;
    this.detach();
    if (gesture.active) {
      removeEmptyCreatedTracks(this.deps.engine, gesture.createdTrackIds);
      this.maybeAutoCrossfade(gesture);
      this.deps.engine.endTransaction();
      this.deps.setSnapGuideMs(null);
    }
  }

  /**
   * GES-inspired overlap-implies-crossfade, adapted to the no-overlap model:
   * when a move commits flush against a neighbor AND the pointer actually
   * wanted to overlap it, drop a dissolve sized to the attempted overlap.
   * Opt-in (deps.autoCrossfade); part of the gesture's undo entry.
   */
  private maybeAutoCrossfade(gesture: ClipDragGesture): void {
    const { engine, pxPerMs, autoCrossfade } = this.deps;
    if (!autoCrossfade || gesture.mode !== "move" || gesture.ids.length !== 1) return;
    const anchorId = gesture.ids[0]!;
    const base = gesture.bases.get(anchorId);
    if (!base) return;
    const scroller = this.deps.scrollerRef.current;
    const scrollDx = (scroller?.scrollLeft ?? gesture.startScrollLeft) - gesture.startScrollLeft;
    const desiredStartMs =
      base.startMs + (gesture.lastClientX - gesture.startClientX + scrollDx) / pxPerMs;
    const command = planAutoCrossfade(engine.project, { elementId: anchorId, desiredStartMs });
    if (command) {
      try {
        engine.dispatch(command);
      } catch {
        // Audio-only pair or clips too short for a window: skip silently.
      }
    }
  }

  private cancel(): void {
    const gesture = this.gesture;
    if (!gesture) return;
    this.gesture = null;
    this.detach();
    if (gesture.active) {
      // Rolls back everything since activate(), created tracks included.
      this.deps.engine.cancelTransaction();
      this.deps.setSnapGuideMs(null);
    }
  }

  // -- auto-scroll ------------------------------------------------------------

  private startAutoScroll(): void {
    if (this.autoScrollFrame !== null) return;
    const tick = () => {
      const gesture = this.gesture;
      const scroller = this.deps.scrollerRef.current;
      if (!gesture?.active || !scroller) {
        this.autoScrollFrame = null;
        return;
      }
      const rect = scroller.getBoundingClientRect();
      const dx = edgeScrollSpeed(gesture.lastClientX, rect.left + TIMELINE_HEADER_WIDTH, rect.right);
      const dy = edgeScrollSpeed(gesture.lastClientY, rect.top + RULER_HEIGHT, rect.bottom);
      let scrolled = false;
      if (dx !== 0) {
        const next = Math.max(0, Math.min(scroller.scrollLeft + dx, scroller.scrollWidth - scroller.clientWidth));
        if (next !== scroller.scrollLeft) {
          scroller.scrollLeft = next;
          scrolled = true;
        }
      }
      if (dy !== 0) {
        const next = Math.max(0, Math.min(scroller.scrollTop + dy, scroller.scrollHeight - scroller.clientHeight));
        if (next !== scroller.scrollTop) {
          scroller.scrollTop = next;
          scrolled = true;
        }
      }
      if (scrolled) this.update();
      this.autoScrollFrame = requestAnimationFrame(tick);
    };
    this.autoScrollFrame = requestAnimationFrame(tick);
  }

  // -- move/trim resolution ----------------------------------------------------

  private update(): void {
    const gesture = this.gesture;
    if (!gesture?.active) return;
    const { engine, pxPerMs, snapEnabled, setSnapGuideMs } = this.deps;
    const scroller = this.deps.scrollerRef.current;
    // Fold scroll deltas in so auto-scroll (and mid-drag wheel) keeps the
    // clip under the pointer.
    const scrollDx = (scroller?.scrollLeft ?? gesture.startScrollLeft) - gesture.startScrollLeft;
    const deltaRawMs = (gesture.lastClientX - gesture.startClientX + scrollDx) / pxPerMs;
    const liveProject = engine.project;
    const anchorId = gesture.ids[0]!;
    const anchorBase = gesture.bases.get(anchorId)!;
    const { ignore, targets } = gesture;
    const thresholdMs = SNAP_PX / pxPerMs;

    try {
      if (gesture.mode === "move") {
        const snapping = snapEnabled && !(gesture.lastAltKey && !gesture.duplicated);
        const snapped = snapClip(anchorBase.startMs + deltaRawMs, anchorBase.durationMs, targets, thresholdMs, {
          enabled: snapping,
          fps: liveProject.fps,
        });
        let guide = snapped.guideMs;
        let deltaMs = Math.round(snapped.ms - anchorBase.startMs);
        const minStart = Math.min(...gesture.ids.map((id) => gesture.bases.get(id)!.startMs));
        deltaMs = Math.max(deltaMs, -minStart);

        if (gesture.ids.length === 1) {
          // Target the lane under the pointer (rows render reversed: the top
          // row is the last track). Outside the rows — above the top lane or
          // below the bottom one — the gesture grows a new track on that side.
          const trackCount = liveProject.tracks.length;
          let targetIndex = anchorBase.trackIndex;
          if (scroller) {
            const rect = scroller.getBoundingClientRect();
            const contentY = gesture.lastClientY - rect.top + scroller.scrollTop;
            const visualRow = Math.floor(
              (contentY - RULER_HEIGHT - NEW_TRACK_LANE_HEIGHT) / TRACK_HEIGHT,
            );
            targetIndex = trackCount - 1 - visualRow;
          }
          let targetTrack: Track | undefined;
          if (
            (targetIndex >= trackCount || targetIndex < 0) &&
            gesture.createdTrackIds.length === 0
          ) {
            const trackId = createTrackId();
            engine.dispatch({
              type: "addTrack",
              id: trackId,
              ...(targetIndex < 0 ? { index: 0 } : {}),
            });
            gesture.createdTrackIds.push(trackId);
            targetTrack = engine.project.tracks.find((track) => track.id === trackId);
          } else {
            targetIndex = Math.max(0, Math.min(targetIndex, trackCount - 1));
            targetTrack = liveProject.tracks[targetIndex];
          }
          if (!targetTrack) return;
          if (targetTrack.locked) return;
          let startMs = anchorBase.startMs + deltaMs;
          if (targetTrack.magnetic) {
            // Magnetic: the engine's slot rule places the clip; raw pointer
            // position chooses the slot and edge-snapping would fight it.
            startMs = Math.max(0, Math.round(anchorBase.startMs + deltaRawMs));
            guide = null;
          } else if (!canPlaceIgnoring(targetTrack, startMs, anchorBase.durationMs, ignore)) {
            // Blocked: hold the last valid placement instead of teleporting
            // to a free slot; the move resolves when the pointer reaches
            // free space (and the commit is always the last valid state).
            setSnapGuideMs(null);
            return;
          }
          engine.dispatch({
            type: "moveElement",
            elementId: anchorId,
            startMs,
            toTrackId: targetTrack.id,
          });
        } else {
          // Group move: time-shift only, all-or-nothing.
          const placements = gesture.ids.map((id) => {
            const base = gesture.bases.get(id)!;
            return {
              id,
              startMs: base.startMs + deltaMs,
              durationMs: base.durationMs,
              track: liveProject.tracks[base.trackIndex],
            };
          });
          const allFit = placements.every(
            (p) =>
              p.track &&
              (p.track.magnetic || canPlaceIgnoring(p.track, p.startMs, p.durationMs, ignore)),
          );
          if (allFit) {
            for (const p of placements) {
              engine.dispatch({ type: "moveElement", elementId: p.id, startMs: p.startMs });
            }
          } else {
            guide = null;
          }
        }
        setSnapGuideMs(guide);
        return;
      }

      const snapping = snapEnabled && !gesture.lastAltKey;

      if (gesture.mode === "slip") {
        // Dragging right slides the filmstrip right — earlier source at the
        // in point — so the trim delta is the pointer delta negated.
        const range = gesture.slipRange ?? { minMs: -Infinity, maxMs: Infinity };
        const wanted = Math.max(range.minMs, Math.min(range.maxMs, -Math.round(deltaRawMs)));
        const stepMs = wanted - gesture.appliedDeltaMs;
        if (stepMs !== 0) {
          for (const id of gesture.ids) {
            const element = getElementLocation(liveProject, id)?.element;
            if (!element) continue;
            if (element.type !== "video" && element.type !== "audio" && element.type !== "multicam") continue;
            engine.dispatch({ type: "slipElement", elementId: id, deltaMs: stepMs });
          }
          gesture.appliedDeltaMs = wanted;
        }
        setSnapGuideMs(null);
        return;
      }

      if (gesture.mode === "slide") {
        const snapped = snapClip(anchorBase.startMs + deltaRawMs, anchorBase.durationMs, targets, thresholdMs, {
          enabled: snapping,
          fps: liveProject.fps,
        });
        const wanted = Math.round(snapped.ms) - anchorBase.startMs;
        const stepMs = wanted - gesture.appliedDeltaMs;
        if (stepMs !== 0) {
          // Throws when a neighbor hits its minimum: applied stays, the clip
          // holds at the last valid spot.
          engine.dispatch({ type: "slideElement", elementId: anchorId, deltaMs: stepMs });
          gesture.appliedDeltaMs = wanted;
        }
        setSnapGuideMs(gesture.appliedDeltaMs === wanted ? snapped.guideMs : null);
        return;
      }

      if (gesture.mode === "roll-start" || gesture.mode === "roll-end") {
        const cutBaseMs =
          gesture.mode === "roll-end" ? anchorBase.startMs + anchorBase.durationMs : anchorBase.startMs;
        const snapped = snapTime(cutBaseMs + deltaRawMs, targets, thresholdMs, {
          enabled: snapping,
          fps: liveProject.fps,
        });
        const wanted = Math.round(snapped.ms) - cutBaseMs;
        const rollId = gesture.mode === "roll-end" ? anchorId : gesture.rollTargetId;
        if (!rollId) return;
        const stepMs = wanted - gesture.appliedDeltaMs;
        if (stepMs !== 0) {
          engine.dispatch({ type: "rollEdit", elementId: rollId, deltaMs: stepMs });
          gesture.appliedDeltaMs = wanted;
        }
        setSnapGuideMs(gesture.appliedDeltaMs === wanted ? snapped.guideMs : null);
        return;
      }

      if (gesture.mode === "ripple-start" || gesture.mode === "ripple-end") {
        const edge = gesture.mode === "ripple-end" ? ("end" as const) : ("start" as const);
        const edgeBaseMs =
          edge === "end" ? anchorBase.startMs + anchorBase.durationMs : anchorBase.startMs;
        // Downstream clips move with a ripple, so their edges are unreliable
        // magnets — snap only to the stationary kinds.
        const rippleTargets = targets.filter(
          (t) => t.kind === "marker" || t.kind === "playhead" || t.kind === "origin",
        );
        const snapped = snapTime(edgeBaseMs + deltaRawMs, rippleTargets, thresholdMs, {
          enabled: snapping,
          fps: liveProject.fps,
        });
        const wanted = Math.round(snapped.ms) - edgeBaseMs;
        const stepMs = wanted - gesture.appliedDeltaMs;
        if (stepMs !== 0) {
          engine.dispatch({ type: "rippleTrim", elementId: anchorId, edge, deltaMs: stepMs });
          gesture.appliedDeltaMs = wanted;
        }
        setSnapGuideMs(gesture.appliedDeltaMs === wanted ? snapped.guideMs : null);
        return;
      }

      // Trims cascade across the whole gesture (the grabbed clip plus its
      // linked partners): one shared delta, clamped so every member fits,
      // keeps linked video/audio edges in sync.
      const members = gesture.ids.flatMap((id) => {
        const base = gesture.bases.get(id);
        if (!base) return [];
        const element = getElementLocation(liveProject, id)?.element;
        const asset =
          element && "assetId" in element ? liveProject.assets[element.assetId] : undefined;
        return [
          {
            id,
            base,
            element,
            assetDurationMs: asset?.durationMs,
            track: liveProject.tracks[base.trackIndex],
          },
        ];
      });
      // All-or-nothing: a partner hitting a neighbor blocks the whole trim,
      // so linked edges never drift apart.
      const allFit = (startMs: (b: ClipDragBase) => number, durationMs: (b: ClipDragBase) => number) =>
        members.every(
          ({ base, track }) => track && canPlaceIgnoring(track, startMs(base), durationMs(base), ignore),
        );

      if (gesture.mode === "trim-end") {
        const endSnap = snapTime(anchorBase.startMs + anchorBase.durationMs + deltaRawMs, targets, thresholdMs, {
          enabled: snapping,
          fps: liveProject.fps,
        });
        const wantedDelta = Math.round(endSnap.ms) - (anchorBase.startMs + anchorBase.durationMs);
        let deltaMs = wantedDelta;
        for (const { base, assetDurationMs } of members) {
          // Growing the end consumes later source (forward) or earlier
          // source (reversed); a timeMap freezes at its boundary instead.
          if (!base.hasTimeMap && assetDurationMs !== undefined && base.trimStartMs !== undefined) {
            deltaMs = Math.min(
              deltaMs,
              base.reversed
                ? base.trimStartMs
                : assetDurationMs - base.trimStartMs - base.durationMs,
            );
          }
          deltaMs = Math.max(deltaMs, MIN_ELEMENT_DURATION_MS - base.durationMs);
        }
        const fits = allFit((b) => b.startMs, (b) => b.durationMs + deltaMs);
        if (fits) {
          for (const { id, base, element } of members) {
            if (!element) continue;
            // trimEdge keeps content anchored (reversed/speed-aware); the
            // step is the remaining distance from the LIVE element state.
            const stepMs = base.startMs + base.durationMs + deltaMs - (element.startMs + element.durationMs);
            if (stepMs !== 0) {
              engine.dispatch({ type: "trimEdge", elementId: id, edge: "end", deltaMs: stepMs });
            }
          }
        }
        setSnapGuideMs(fits && deltaMs === wantedDelta ? endSnap.guideMs : null);
        return;
      }

      // trim-start
      const startSnap = snapTime(anchorBase.startMs + deltaRawMs, targets, thresholdMs, {
        enabled: snapping,
        fps: liveProject.fps,
      });
      const wantedShift = Math.round(startSnap.ms) - anchorBase.startMs;
      let shift = wantedShift;
      for (const { base, assetDurationMs } of members) {
        shift = Math.max(shift, -base.startMs);
        // Growing the start reveals earlier source (forward) or later
        // source (reversed); reversed speed ramps can't grow their head.
        if (!base.hasTimeMap && base.trimStartMs !== undefined) {
          shift = Math.max(
            shift,
            base.reversed && assetDurationMs !== undefined
              ? -(assetDurationMs - base.trimStartMs - base.durationMs)
              : -base.trimStartMs,
          );
        }
        if (base.hasTimeMap && base.reversed) shift = Math.max(shift, 0);
        shift = Math.min(shift, base.durationMs - MIN_ELEMENT_DURATION_MS);
      }
      const fits = allFit((b) => b.startMs + shift, (b) => b.durationMs - shift);
      if (fits) {
        for (const { id, base, element } of members) {
          if (!element) continue;
          const stepMs = base.startMs + shift - element.startMs;
          if (stepMs !== 0) {
            engine.dispatch({ type: "trimEdge", elementId: id, edge: "start", deltaMs: stepMs });
          }
        }
      }
      setSnapGuideMs(fits && shift === wantedShift ? startSnap.guideMs : null);
    } catch {
      // Engine rejected (overlap/bounds): keep last valid state.
    }
  }
}

