const TRIM_HANDLE_PX = 9;

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function clipLabel(element: TimelineElement, asset?: AssetRef): string {
  if (element.type === "text" || element.type === "caption") return element.text;
  if (element.type === "multicam") {
    return `Multicam (${element.sources.map((s) => s.key).join(" + ")})`;
  }
  return asset?.name ?? element.type;
}

// ---------------------------------------------------------------------------
// Clip
// ---------------------------------------------------------------------------

// Clip-type color tokens live in globals.css under [data-editor]; alpha is
// baked into the tokens, so no opacity modifiers here.

/**
 * Waveform of the multicam's playing audio: the source named by
 * `audioSource` (all sources are muted when it's unset, so draw nothing).
 */
function MulticamWaveform({
  element,
  widthPx,
  heightPx,
}: {
  element: TimelineElement & { type: "multicam" };
  widthPx: number;
  heightPx: number;
}) {
  const source = element.sources.find((s) => s.key === element.audioSource);
  const asset = useEditorState((s) => (source ? s.project.assets[source.assetId] : undefined));
  if (!source || !asset) return null;
  return (
    <AudioWaveform
      asset={asset}
      widthPx={widthPx}
      heightPx={Math.round(heightPx * 0.35)}
      trimStartMs={source.trimStartMs}
      durationMs={element.durationMs}
      timeMap={element.timeMap}
      variant="strip"
      color="rgba(255, 255, 255, 0.65)"
    />
  );
}

/**
 * Multicam clip internals: one label per cut span (the layout it shows) and
 * a draggable tick at every cut. Drag retimes (moveAngleCut, one undo per
 * gesture); alt-click removes the cut.
 */
function MulticamCutTicks({
  element,
  pxPerMs,
}: {
  element: TimelineElement & { type: "multicam" };
  pxPerMs: number;
}) {
  const engine = useEditor();
  const layouts = useEditorState((s) => s.project.layouts);
  const dragRef = useRef<{ fromMs: number; startClientX: number } | null>(null);

  const layoutName = (layoutId: string) =>
    layouts.find((l) => l.id === layoutId)?.name ?? "?";

  return (
    <>
      {element.angles.map((cut, i) => {
        const nextAt = element.angles[i + 1]?.atMs ?? element.durationMs;
        const width = Math.max(0, (nextAt - cut.atMs) * pxPerMs);
        return (
          <span
            key={`span-${cut.atMs}`}
            className="pointer-events-none absolute bottom-0.5 z-10 truncate px-1.5 text-2xs text-overlay-foreground/75"
            style={{ left: cut.atMs * pxPerMs, maxWidth: width }}
          >
            {layoutName(cut.layoutId)}
          </span>
        );
      })}
      {/* Keyed by index, not atMs: retiming changes atMs on every move, and a
          key change would remount the tick mid-drag and kill its pointer
          capture (stranding the open transaction). */}
      {element.angles.slice(1).map((cut, i) => (
        <span
          key={`tick-${i}`}
          title="Drag to retime the cut · ⌥-click to remove"
          className="absolute inset-y-0 z-30 w-[7px] -translate-x-1/2 cursor-col-resize"
          style={{ left: cut.atMs * pxPerMs }}
          onPointerDown={(event) => {
            event.stopPropagation();
            if (event.altKey) {
              try {
                engine.dispatch({ type: "removeAngleCut", elementId: element.id, atMs: cut.atMs });
              } catch {
                // Cut vanished.
              }
              return;
            }
            dragRef.current = { fromMs: cut.atMs, startClientX: event.clientX };
            engine.beginTransaction();
            event.currentTarget.setPointerCapture(event.pointerId);
          }}
          onPointerMove={(event) => {
            const drag = dragRef.current;
            if (!drag) return;
            const toMs = Math.round(drag.fromMs + (event.clientX - drag.startClientX) / pxPerMs);
            try {
              engine.dispatch({
                type: "moveAngleCut",
                elementId: element.id,
                fromMs: drag.fromMs,
                toMs,
              });
              drag.fromMs = Math.max(1, toMs);
            } catch {
              // Clamped into a neighbor: keep the last good position.
            }
          }}
          onPointerUp={(event) => {
            if (!dragRef.current) return;
            dragRef.current = null;
            engine.endTransaction();
            event.currentTarget.releasePointerCapture(event.pointerId);
          }}
        >
          <span className="absolute inset-y-0 left-1/2 w-0.5 -translate-x-1/2 bg-overlay-foreground/80" />
        </span>
      ))}
    </>
  );
}

// Memoized: a clip drag dispatches per frame and re-renders its lane; with
// structural sharing only the moved element changes identity, so sibling
// clips bail here. Subscriptions are narrow (own selection flag, own asset)
// for the same reason — never the whole project.
export const Clip = memo(function Clip({
  element,
  track,
  pxPerMs,
}: {
  element: TimelineElement;
  track: Track;
  pxPerMs: number;
}) {
  const engine = useEditor();
  const clipDrag = useClipDrag();
  const { timelineTool } = useEditorUI();
  const selected = useEditorState((s) => s.selection.elementIds.includes(element.id));
  const multiSelected = useEditorState((s) => s.selection.elementIds.length >= 2);
  const asset = useEditorState((s) =>
    "assetId" in element ? s.project.assets[element.assetId] : undefined,
  );
  const widthPx = Math.max(10, element.durationMs * pxPerMs);
  const heightPx = TRACK_HEIGHT - 8;
  const label = clipLabel(element, asset);

  // The press only picks the gesture (selection + move vs trim); the shared
  // controller owns it from here via window listeners, so the gesture
  // survives this clip remounting under another lane mid-drag.
  const beginDrag = (event: ReactPointerEvent<HTMLDivElement>) => {
    if (event.button !== 0) return;
    event.stopPropagation();

    const selectionIds = engine.selection.elementIds;
    // Linked partners (shared linkId, e.g. a video and its detached audio)
    // select, move, and trim as one; this clip first so it anchors gestures.
    const linkGroup = getLinkedElementIds(engine.project, element.id);
    if (event.shiftKey) {
      const others = selectionIds.filter((id) => !linkGroup.includes(id));
      engine.select(selected ? others : [...others, ...linkGroup]);
      return;
    }
    const ids = selected && selectionIds.length > linkGroup.length
      ? [...linkGroup, ...selectionIds.filter((id) => !linkGroup.includes(id))]
      : [...linkGroup];
    if (!selected) engine.select([...linkGroup]);

    const rect = event.currentTarget.getBoundingClientRect();
    const offsetX = event.clientX - rect.left;
    // Trim when the gesture is just this clip (plus linked partners, which
    // the drag controller trims in lockstep). The active tool decides what
    // the handles and the body do; the controller degrades unmet tool
    // gestures (no neighbor to roll/slide against, nothing to slip) back to
    // the plain trim/move.
    const soloClip = ids.length === linkGroup.length;
    let mode: ClipDragMode = "move";
    if (soloClip && timelineTool === "slip") mode = "slip";
    else if (soloClip && timelineTool === "slide") mode = "slide";
    else if (soloClip && offsetX <= TRIM_HANDLE_PX) {
      mode =
        timelineTool === "ripple" ? "ripple-start" : timelineTool === "roll" ? "roll-start" : "trim-start";
    } else if (soloClip && offsetX >= rect.width - TRIM_HANDLE_PX) {
      mode = timelineTool === "ripple" ? "ripple-end" : timelineTool === "roll" ? "roll-end" : "trim-end";
    }

    clipDrag.begin(event, { mode, ids, duplicateOnDrag: event.altKey && mode === "move" });
  };

  const playheadInside = () => {
    const t = engine.playback.state.currentTimeMs;
    return t > element.startMs && t < element.startMs + element.durationMs;
  };

  const isVisual =
    element.type === "video" || element.type === "image" || element.type === "text";
  const cutMs = element.startMs + element.durationMs;
  const nextAdjacent = track.elements.find((e) => e.startMs === cutMs && e.id !== element.id);
  const transition = "transition" in element ? element.transition : undefined;
  const speed = element.type === "video" || element.type === "audio" ? getAverageSpeed(element) : 1;
  const isReversed =
    (element.type === "video" || element.type === "audio") && element.reversed === true;
  const dispatchSafe = (command: Record<string, unknown> & { type: string }) => {
    try {
      engine.dispatch(command);
    } catch {
      // Rejected (overlap/bounds): timeline resyncs from state.
    }
  };

  return (
    <ContextMenu>
      <ContextMenuTrigger
        render={
          <div
            data-mcut-clip={element.type}
            className={cn(
              // left-0 + translateX: moves stay off the layout path (left
              // would relayout every absolutely-positioned sibling per frame).
              "group absolute top-1 bottom-1 left-0 flex cursor-grab items-center overflow-hidden rounded-lg text-xs font-medium shadow-sm select-none active:cursor-grabbing",
              getElementUI(element.type).clipClassName,
              selected
                ? "ring-2 ring-overlay-foreground"
                : "ring-1 ring-overlay-foreground/10 hover:ring-overlay-foreground/30",
            )}
            style={{
              transform: `translateX(${element.startMs * pxPerMs}px)`,
              width: widthPx,
            }}
            onPointerDown={beginDrag}
            onContextMenu={() => {
              if (!selected) engine.select(getLinkedElementIds(engine.project, element.id));
            }}
            title={label}
          />
        }
      >
        {element.type === "video" && asset && (
          <>
            <VideoFilmstrip
              asset={asset}
              widthPx={widthPx}
              heightPx={heightPx}
              trimStartMs={element.trimStartMs}
              durationMs={element.durationMs}
              timeMap={element.timeMap}
              reversed={element.reversed}
              className="opacity-90"
            />
            <AudioWaveform
              asset={asset}
              widthPx={widthPx}
              heightPx={Math.round(heightPx * 0.35)}
              trimStartMs={element.trimStartMs}
              durationMs={element.durationMs}
              timeMap={element.timeMap}
              reversed={element.reversed}
              variant="strip"
              color="rgba(255, 255, 255, 0.65)"
            />
          </>
        )}
        {element.type === "audio" && asset && (
          <AudioWaveform
            asset={asset}
            widthPx={widthPx}
            heightPx={heightPx}
            trimStartMs={element.trimStartMs}
            durationMs={element.durationMs}
            timeMap={element.timeMap}
            reversed={element.reversed}
            color="rgba(167, 243, 208, 0.9)"
          />
        )}
        {element.type === "audio" && (
          <VolumeBand
            element={element}
            widthPx={widthPx}
            heightPx={heightPx + 8}
            interactive={selected}
          />
        )}
        {element.type === "multicam" && <MulticamWaveform element={element} widthPx={widthPx} heightPx={heightPx} />}
        {element.type === "multicam" && <MulticamCutTicks element={element} pxPerMs={pxPerMs} />}
        {(element.type === "video" || element.type === "audio" || element.type === "multicam") && (
          <FadeOverlay element={element} pxPerMs={pxPerMs} widthPx={widthPx} interactive={selected} />
        )}
        {selected && <KeyframeMarkers element={element} pxPerMs={pxPerMs} />}
        {(speed !== 1 || isReversed) && (
          <span className="pointer-events-none absolute top-0.5 right-2.5 z-10 rounded-sm bg-overlay/60 px-1 font-mono text-2xs text-overlay-foreground/90">
            {[speed !== 1 ? `${Number(speed.toFixed(2))}x` : null, isReversed ? "◀" : null]
              .filter(Boolean)
              .join(" ")}
          </span>
        )}
        {element.linkId && (
          <span
            title="Linked: selects and edits with its partner clip"
            className="pointer-events-none absolute top-0.5 left-2.5 z-10 rounded-sm bg-overlay/60 p-0.5 text-overlay-foreground/90"
          >
            <LinkIcon className="size-2.5" />
          </span>
        )}
        {transition && (
          <span
            title={
              nextAdjacent
                ? `${transition.type} → next clip`
                : "Transition inactive (next clip not flush)"
            }
            className={cn(
              "absolute top-1/2 right-[3px] z-30 size-2 -translate-y-1/2 rotate-45 rounded-[2px]",
              nextAdjacent ? "bg-(--snap-guide) ring-1 ring-overlay/40" : "bg-overlay-foreground/30",
            )}
          />
        )}
        <span
          className={cn(
            "pointer-events-none relative z-10 truncate px-2",
            (element.type === "video" || element.type === "audio") &&
              "rounded-sm bg-overlay/55 py-0.5 text-2xs mx-1.5",
          )}
        >
          {label}
        </span>
        {/* Trim brackets */}
        <span
          className={cn(
            // w-[9px]: trim-handle hit target tuned to sit inside the clip's 10px end caps.
            "absolute inset-y-0 left-0 z-20 flex w-[9px] cursor-ew-resize items-center justify-center bg-overlay-foreground/0 transition-colors",
            selected ? "bg-overlay-foreground/90" : "group-hover:bg-overlay-foreground/40",
          )}
        >
          <span
            className={cn(
              "h-3.5 w-0.5 rounded-full",
              selected ? "bg-overlay/70" : "bg-overlay-foreground/70",
            )}
          />
        </span>
        <span
          className={cn(
            "absolute inset-y-0 right-0 z-20 flex w-[9px] cursor-ew-resize items-center justify-center bg-overlay-foreground/0 transition-colors",
            selected ? "bg-overlay-foreground/90" : "group-hover:bg-overlay-foreground/40",
          )}
        >
          <span
            className={cn(
              "h-3.5 w-0.5 rounded-full",
              selected ? "bg-overlay/70" : "bg-overlay-foreground/70",
            )}
          />
        </span>
      </ContextMenuTrigger>
      <ContextMenuContent>
        <ContextMenuItem
          disabled={!playheadInside()}
          onClick={() => splitSelectionAtPlayhead(engine)}
        >
          Split at playhead
          <span className="ml-auto pl-4 font-mono text-2xs text-muted-foreground">S</span>
        </ContextMenuItem>
        <ContextMenuItem onClick={() => duplicateElement(engine, element.id)}>
          Duplicate
        </ContextMenuItem>
        {(element.type === "video" || element.type === "audio") && (
          <ContextMenuItem
            onClick={() =>
              engine.dispatch({
                type: "updateElement",
                elementId: element.id,
                patch: { muted: !element.muted },
              })
            }
          >
            {element.muted ? "Unmute" : "Mute"}
          </ContextMenuItem>
        )}
        {element.type === "video" && (
          <ContextMenuItem
            disabled={element.muted}
            onClick={() => dispatchSafe({ type: "detachAudio", elementId: element.id })}
          >
            Detach audio
          </ContextMenuItem>
        )}
        {element.linkId && (
          <ContextMenuItem onClick={() => unlinkElements(engine, element.id)}>
            Unlink
          </ContextMenuItem>
        )}
        {(element.type === "video" || element.type === "audio") && (
          <ContextMenuSub>
            <ContextMenuSubTrigger>Speed</ContextMenuSubTrigger>
            <ContextMenuSubContent>
              {/* Signed percentages: negative plays the source backward. */}
              {[25, 50, 100, 150, 200, 400, -100].map((pct) => (
                <ContextMenuItem
                  key={pct}
                  onClick={() => {
                    try {
                      engine.transact(() => {
                        engine.dispatch({
                          type: "setElementSpeed",
                          elementId: element.id,
                          speed: Math.abs(pct) / 100,
                        });
                        if ((pct < 0) !== (element.reversed ?? false)) {
                          engine.dispatch({
                            type: "updateElement",
                            elementId: element.id,
                            patch: { reversed: pct < 0 || undefined },
                          });
                        }
                      });
                    } catch {
                      // Rejected (overlap after rescale): timeline resyncs.
                    }
                  }}
                >
                  {pct}%{pct === -100 && " (reverse)"}
                  {Math.abs(speed * (element.reversed ? -100 : 100) - pct) < 0.5 && (
                    <span className="ml-auto pl-4 text-2xs text-muted-foreground">✓</span>
                  )}
                </ContextMenuItem>
              ))}
            </ContextMenuSubContent>
          </ContextMenuSub>
        )}
        {element.type === "multicam" && (
          <ContextMenuItem
            onClick={() => dispatchSafe({ type: "flattenMulticam", elementId: element.id })}
          >
            Flatten multicam
          </ContextMenuItem>
        )}
        {element.type === "video" && multiSelected && (
          <ContextMenuItem
            onClick={() => {
              const videoIds = engine.selection.elementIds.filter((id) =>
                engine.project.tracks.some((t) =>
                  t.elements.some((e) => e.id === id && e.type === "video"),
                ),
              );
              dispatchSafe({ type: "createMulticam", elementIds: videoIds });
            }}
          >
            Create multicam from selection
          </ContextMenuItem>
        )}
        {isVisual &&
          (transition ? (
            <ContextMenuItem
              onClick={() =>
                dispatchSafe({ type: "setTransition", elementId: element.id, transition: null })
              }
            >
              Remove transition
            </ContextMenuItem>
          ) : nextAdjacent ? (
            <ContextMenuSub>
              <ContextMenuSubTrigger>Transition into next</ContextMenuSubTrigger>
              <ContextMenuSubContent>
                {listTransitionTypes().map((type) => (
                  <ContextMenuItem
                    key={type}
                    className="capitalize"
                    onClick={() =>
                      dispatchSafe({
                        type: "setTransition",
                        elementId: element.id,
                        transition: { type, durationMs: 500 },
                      })
                    }
                  >
                    {type.replace("-", " ")}
                  </ContextMenuItem>
                ))}
              </ContextMenuSubContent>
            </ContextMenuSub>
          ) : null)}
        <ContextMenuSeparator />
        <ContextMenuItem variant="destructive" onClick={() => removeSelection(engine)}>
          Delete
          <span className="ml-auto pl-4 font-mono text-2xs text-muted-foreground">⌫</span>
        </ContextMenuItem>
      </ContextMenuContent>
    </ContextMenu>
  );
});

"use client";

// Track rows: header controls, sortable clip lanes with dnd-kit drop targets, and the drop ghost overlay.

import { createElement, memo, useState } from "react";
import { useDroppable } from "@dnd-kit/core";
import { useSortable } from "@dnd-kit/sortable";
import { CSS } from "@dnd-kit/utilities";
import {
  EyeIcon,
  EyeOffIcon,
  GripVerticalIcon,
  LayersIcon,
  LockIcon,
  LockOpenIcon,
  MagnetIcon,
  Volume2Icon,
  VolumeXIcon,
  XIcon,
} from "@/lib/hugeicons";
import { useEditor, useEditorState } from "@mcut/react";
import { type Track } from "@mcut/timeline";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import {
  ContextMenu,
  ContextMenuContent,
  ContextMenuItem,
  ContextMenuSeparator,
  ContextMenuTrigger,
} from "@/components/ui/context-menu";
import { Input } from "@/components/ui/input";
import { getElementUI } from "./element-ui";
import { isSoloTrack, selectTrackElements, toggleSoloTrack } from "./editor-actions";
import { type LaneDropData } from "./editor-dnd";
import { TIMELINE_HEADER_WIDTH, useDropPreview } from "./editor-ui";
import { formatTimecode } from "./format";
import { NEW_TRACK_LANE_HEIGHT, RULER_HEIGHT, TRACK_HEIGHT } from "./timeline-drag";
import { Clip } from "./timeline-clip";

export const HEADER_WIDTH = TIMELINE_HEADER_WIDTH;

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function trackIcon(track: Track) {
  const first = track.elements[0]?.type;
  if (!first) return LayersIcon;
  return getElementUI(first).icon;
}

// ---------------------------------------------------------------------------
// Track header + lane
// ---------------------------------------------------------------------------

function TrackHeader({
  track,
  gripProps,
}: {
  track: Track;
  gripProps?: Record<string, unknown>;
}) {
  const engine = useEditor();
  const [renaming, setRenaming] = useState(false);
  const setFlag = (patch: Partial<Pick<Track, "muted" | "hidden" | "locked" | "magnetic">>) =>
    engine.dispatch({ type: "setTrackFlags", trackId: track.id, ...patch });
  // Subscriptions, not engine.project reads: these depend on OTHER tracks'
  // flags, which no longer reach this memoized row as props.
  const timelineMagnetEnabled = useEditorState((s) =>
    s.project.tracks.some((candidate) => candidate.magnetic),
  );
  const solo = useEditorState(() => isSoloTrack(engine, track.id));
  const setTimelineMagnet = (magnetic: boolean) => {
    const tracks = [...engine.project.tracks];
    engine.transact(() => {
      for (const candidate of tracks) {
        // Caption tracks keep transcript timing — never compact them.
        const isCaptionTrack =
          candidate.elements.length > 0 && candidate.elements.every((e) => e.type === "caption");
        if (isCaptionTrack) continue;
        if (candidate.magnetic !== magnetic) {
          engine.dispatch({ type: "setTrackFlags", trackId: candidate.id, magnetic });
        }
      }
    });
  };

  return (
    <ContextMenu>
      <ContextMenuTrigger
        render={
          <div
            className="group/header sticky left-0 z-50 flex shrink-0 items-center gap-1 border-r border-foreground/10 bg-card pr-2 pl-0.5"
            style={{ width: HEADER_WIDTH, height: TRACK_HEIGHT }}
            onClick={(event) => {
              // Header click selects the track's clips (buttons handle themselves).
              if ((event.target as HTMLElement).closest("button, input")) return;
              selectTrackElements(engine, track.id);
            }}
          />
        }
      >
        <button
          type="button"
          className="cursor-grab touch-none text-muted-foreground/50 hover:text-muted-foreground"
          aria-label="Reorder track"
          {...gripProps}
        >
          <GripVerticalIcon className="size-3.5" />
        </button>
        {createElement(trackIcon(track), {
          className: "size-3.5 shrink-0 text-muted-foreground",
        })}
        {renaming ? (
          <Input
            autoFocus
            defaultValue={track.name}
            className="h-5 flex-1 px-1 text-2xs"
            onBlur={(e) => {
              const name = e.target.value.trim();
              if (name && name !== track.name) {
                engine.dispatch({ type: "renameTrack", trackId: track.id, name });
              }
              setRenaming(false);
            }}
            onKeyDown={(e) => {
              if (e.key === "Enter") (e.target as HTMLInputElement).blur();
              if (e.key === "Escape") setRenaming(false);
            }}
          />
        ) : (
          <span
            className="min-w-6 flex-1 truncate text-2xs font-medium"
            onDoubleClick={() => setRenaming(true)}
          >
            {track.name}
          </span>
        )}
        <Button
          variant="ghost"
          size="icon-xs"
          className="size-5"
          title={track.muted ? "Unmute track" : "Mute track"}
          onClick={() => setFlag({ muted: !track.muted })}
        >
          {track.muted ? <VolumeXIcon className="text-destructive" /> : <Volume2Icon />}
        </Button>
        <Button
          variant="ghost"
          size="icon-xs"
          className="size-5"
          title={track.hidden ? "Show track" : "Hide track"}
          onClick={() => setFlag({ hidden: !track.hidden })}
        >
          {track.hidden ? <EyeOffIcon className="text-destructive" /> : <EyeIcon />}
        </Button>
        <Button
          variant="ghost"
          size="icon-xs"
          className="size-5"
          title={track.locked ? "Unlock track" : "Lock track"}
          onClick={() => setFlag({ locked: !track.locked })}
        >
          {track.locked ? <LockIcon className="text-destructive" /> : <LockOpenIcon />}
        </Button>
        <Button
          variant="ghost"
          size="icon-xs"
          className={cn("size-5", timelineMagnetEnabled ? "bg-primary/20 text-primary" : "text-muted-foreground")}
          title={timelineMagnetEnabled ? "Disable timeline magnet" : "Enable timeline magnet"}
          onClick={() => setTimelineMagnet(!timelineMagnetEnabled)}
        >
          <MagnetIcon />
        </Button>
        <Button
          variant="ghost"
          size="icon-xs"
          className={cn(
            "size-5 font-mono text-2xs font-bold",
            solo ? "bg-primary/20 text-primary" : "text-muted-foreground",
          )}
          title="Solo track (mute all others)"
          onClick={() => toggleSoloTrack(engine, track.id)}
        >
          S
        </Button>
        <Button
          variant="ghost"
          size="icon-xs"
          className="size-5 opacity-0 transition-opacity group-hover/header:opacity-100 hover:text-destructive"
          title="Delete track"
          onClick={() => engine.dispatch({ type: "removeTrack", trackId: track.id })}
        >
          <XIcon />
        </Button>
      </ContextMenuTrigger>
      <ContextMenuContent>
        <ContextMenuItem onClick={() => selectTrackElements(engine, track.id)}>
          Select clips
        </ContextMenuItem>
        <ContextMenuItem onClick={() => setRenaming(true)}>Rename</ContextMenuItem>
        <ContextMenuItem
          onClick={() => {
            const index = engine.project.tracks.findIndex((t) => t.id === track.id);
            engine.dispatch({ type: "addTrack", index: index + 1 }); // above = later in paint order
          }}
        >
          Insert track above
        </ContextMenuItem>
        <ContextMenuItem
          onClick={() => {
            const index = engine.project.tracks.findIndex((t) => t.id === track.id);
            engine.dispatch({ type: "addTrack", index });
          }}
        >
          Insert track below
        </ContextMenuItem>
        <ContextMenuSeparator />
        <ContextMenuItem
          variant="destructive"
          onClick={() => engine.dispatch({ type: "removeTrack", trackId: track.id })}
        >
          Delete track
        </ContextMenuItem>
      </ContextMenuContent>
    </ContextMenu>
  );
}

/**
 * The lane's droppable lives in its own tiny child: dnd-kit re-renders every
 * useDroppable consumer whenever `over` changes (each lane crossing), and
 * isolating it here keeps those re-renders away from the Lane and its clips.
 */
function LaneDropTarget({ trackId }: { trackId: string }) {
  const { setNodeRef, isOver } = useDroppable({
    id: `lane-${trackId}`,
    data: { laneTrackId: trackId } satisfies LaneDropData,
  });
  return (
    <div
      ref={setNodeRef}
      className={cn("pointer-events-none absolute inset-0", isOver && "bg-primary/5")}
    />
  );
}

// Memoized on track identity: the engine shares structure, so a dispatch
// only changes the touched track — every other lane bails right here.
const Lane = memo(function Lane({
  track,
  pxPerMs,
  contentWidth,
}: {
  track: Track;
  pxPerMs: number;
  contentWidth: number;
}) {
  return (
    <div
      data-mcut-lane={track.id}
      className={cn(
        "relative before:pointer-events-none before:absolute before:inset-x-0 before:inset-y-1 before:rounded-lg before:bg-foreground/[0.045]",
        track.locked && "opacity-60",
        track.hidden && "[&_[data-mcut-clip]]:opacity-50",
      )}
      style={{ width: contentWidth, height: TRACK_HEIGHT }}
    >
      <LaneDropTarget trackId={track.id} />
      {track.elements.map((element) => (
        <Clip key={element.id} element={element} track={track} pxPerMs={pxPerMs} />
      ))}
    </div>
  );
});

export const SortableRow = memo(function SortableRow({
  track,
  pxPerMs,
  contentWidth,
}: {
  track: Track;
  pxPerMs: number;
  contentWidth: number;
}) {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
    id: track.id,
    data: { kind: "track", trackId: track.id },
  });
  return (
    <div
      ref={setNodeRef}
      className={cn("flex", isDragging && "z-40 opacity-70")}
      style={{ transform: CSS.Transform.toString(transform), transition }}
    >
      <TrackHeader track={track} gripProps={{ ...attributes, ...listeners }} />
      <Lane track={track} pxPerMs={pxPerMs} contentWidth={contentWidth} />
    </div>
  );
});

/**
 * Always mounted (the drop affordance just fades in while a drag is live):
 * mounting it on drag start used to shift every row down mid-gesture, which
 * both jolted the rows and forced dnd-kit to re-measure lanes on a timer.
 */
export function NewTrackLane({ contentWidth, dragActive }: { contentWidth: number; dragActive: boolean }) {
  const { setNodeRef, isOver } = useDroppable({
    id: "lane-new-track",
    data: { laneTrackId: "new-track" } satisfies LaneDropData,
  });
  return (
    <div className="flex">
      <div
        className="sticky left-0 z-50 flex shrink-0 items-center justify-center border-r border-foreground/10 bg-card text-2xs text-muted-foreground"
        style={{ width: HEADER_WIDTH, height: NEW_TRACK_LANE_HEIGHT }}
      >
        <span className={cn("transition-opacity", dragActive ? "opacity-100" : "opacity-0")}>
          New track
        </span>
      </div>
      <div
        ref={setNodeRef}
        className={cn(
          "relative before:pointer-events-none before:absolute before:inset-x-1 before:inset-y-0.5 before:rounded-lg before:border before:border-dashed before:border-primary/35 before:opacity-0 before:transition-opacity",
          dragActive && "before:opacity-100",
          isOver && "bg-primary/10",
        )}
        style={{ width: contentWidth, height: NEW_TRACK_LANE_HEIGHT }}
      />
    </div>
  );
}

/**
 * The single drop ghost for media/text drags, rendered as one overlay over
 * the rows (per-lane ghost subscriptions would re-render every lane per
 * pointermove). Subscribes to the drop-preview store, so a drag move
 * re-renders exactly this component.
 */
export function DropGhostOverlay({
  rows,
  pxPerMs,
}: {
  rows: Array<{ track: Track }>;
  pxPerMs: number;
}) {
  const ghost = useDropPreview();
  if (!ghost) return null;
  let top = RULER_HEIGHT + 4;
  let height = NEW_TRACK_LANE_HEIGHT - 8;
  if (ghost.trackId !== "new-track") {
    const row = rows.findIndex(({ track }) => track.id === ghost.trackId);
    if (row === -1) return null;
    top = RULER_HEIGHT + NEW_TRACK_LANE_HEIGHT + row * TRACK_HEIGHT + 4;
    height = TRACK_HEIGHT - 8;
  }
  return (
    <div
      data-mcut-drop-ghost=""
      className="pointer-events-none absolute z-40 flex items-end gap-1.5 overflow-hidden rounded-lg border border-primary/80 bg-primary/25 px-1.5 py-0.5 shadow-[0_14px_32px_rgba(0,0,0,0.45),0_0_0_1px_rgba(255,255,255,0.14),inset_0_1px_0_rgba(255,255,255,0.18)] ring-1 ring-primary/35"
      style={{
        left: HEADER_WIDTH + ghost.startMs * pxPerMs,
        top,
        height,
        width: Math.max(10, ghost.durationMs * pxPerMs),
      }}
    >
      <span className="truncate text-2xs font-medium text-primary">{ghost.label}</span>
      <span className="shrink-0 font-mono text-2xs text-primary/80 tabular-nums">
        {formatTimecode(ghost.startMs)}
      </span>
    </div>
  );
}

"use client";

// Ruler + playhead: scrub-to-seek tick ruler, draggable marker flags and guide lines, the playhead, and the snap guide.

import { useEffect, useMemo, useRef, type PointerEvent as ReactPointerEvent } from "react";
import { useEditor, useEditorState, usePlayback, useProject } from "@mcut/react";
import { type CaptionElement } from "@mcut/timeline";
import { searchCaptions } from "@mcut/transcription";
import { useTranscriptKeywords } from "./transcript-keywords";
import { useEditorUI, useSnapGuideMs } from "./editor-ui";
import { formatRulerLabel } from "./format";
import { RULER_HEIGHT } from "./timeline-drag";
import { HEADER_WIDTH } from "./timeline-tracks";

// ---------------------------------------------------------------------------
// Ruler + playhead
// ---------------------------------------------------------------------------

/**
 * Marker flags on the ruler: click seeks, drag retimes (one undo per
 * gesture), ⌥-click removes. Add/navigate via M / ⇧M / ⌥M or the palette.
 */
function RulerMarkers({ pxPerMs }: { pxPerMs: number }) {
  const engine = useEditor();
  const markers = useEditorState((s) => s.project.markers);
  const dragRef = useRef<{ id: string; startClientX: number; startMs: number; moved: boolean } | null>(
    null,
  );

  return (
    <>
      {markers.map((marker) => (
        <span
          key={marker.id}
          title={`${marker.label ?? "Marker"} · drag to retime · ⌥-click to remove`}
          className="absolute bottom-0 z-10 flex h-3.5 w-[11px] -translate-x-1/2 cursor-pointer justify-center"
          style={{ left: marker.timeMs * pxPerMs }}
          onPointerDown={(event) => {
            event.stopPropagation();
            if (event.button !== 0) return;
            if (event.altKey) {
              try {
                engine.dispatch({ type: "removeMarker", markerId: marker.id });
              } catch {
                // Marker vanished.
              }
              return;
            }
            dragRef.current = {
              id: marker.id,
              startClientX: event.clientX,
              startMs: marker.timeMs,
              moved: false,
            };
            engine.beginTransaction();
            event.currentTarget.setPointerCapture(event.pointerId);
          }}
          onPointerMove={(event) => {
            const drag = dragRef.current;
            if (!drag || drag.id !== marker.id) return;
            if (Math.abs(event.clientX - drag.startClientX) > 3) drag.moved = true;
            if (!drag.moved) return;
            const toMs = Math.max(0, Math.round(drag.startMs + (event.clientX - drag.startClientX) / pxPerMs));
            try {
              engine.dispatch({ type: "updateMarker", markerId: drag.id, timeMs: toMs });
            } catch {
              // Marker vanished mid-drag.
            }
          }}
          onPointerUp={(event) => {
            const drag = dragRef.current;
            if (!drag || drag.id !== marker.id) return;
            dragRef.current = null;
            engine.endTransaction();
            event.currentTarget.releasePointerCapture(event.pointerId);
            if (!drag.moved) engine.seek(marker.timeMs);
          }}
        >
          <span
            className="h-full w-[7px] rounded-[2px] rounded-b-none [clip-path:polygon(0_0,100%_0,100%_60%,50%_100%,0_60%)]"
            style={{ backgroundColor: marker.color ?? "var(--snap-guide)" }}
          />
        </span>
      ))}
    </>
  );
}

/**
 * Soft ticks for transcript keyword occurrences (persisted in the
 * transcript panel): hover names the keyword, click seeks to the word.
 */
function KeywordTicks({ pxPerMs }: { pxPerMs: number }) {
  const engine = useEditor();
  const project = useProject();
  const keywords = useTranscriptKeywords(project.id);
  const occurrences = useMemo(() => {
    if (keywords.length === 0) return [];
    const captions = project.tracks
      .flatMap((track) => track.elements)
      .filter((e): e is CaptionElement => e.type === "caption");
    return keywords.flatMap((keyword) =>
      searchCaptions(captions, keyword).map((match) => ({ keyword, timeMs: match.timeMs })),
    );
  }, [project, keywords]);
  return (
    <>
      {occurrences.map(({ keyword, timeMs }, i) => (
        <button
          key={`${keyword}-${timeMs}-${i}`}
          type="button"
          title={`“${keyword}” — click to seek`}
          className="absolute bottom-0 h-1.5 w-[3px] -translate-x-1/2 cursor-pointer rounded-t-sm bg-(--clip-caption)/70 hover:bg-(--clip-caption)"
          style={{ left: timeMs * pxPerMs }}
          onPointerDown={(event) => event.stopPropagation()}
          onClick={() => engine.seek(timeMs)}
        />
      ))}
    </>
  );
}

/** Thin guide line under each marker, across the full track area. */
export function MarkerLines({ pxPerMs, height }: { pxPerMs: number; height: number }) {
  const markers = useEditorState((s) => s.project.markers);
  return (
    <>
      {markers.map((marker) => (
        <div
          key={marker.id}
          className="pointer-events-none absolute top-0 z-0 w-px opacity-35"
          style={{
            left: HEADER_WIDTH + marker.timeMs * pxPerMs,
            height,
            backgroundColor: marker.color ?? "var(--snap-guide)",
          }}
        />
      ))}
    </>
  );
}

export function Ruler({ pxPerMs, contentWidth }: { pxPerMs: number; contentWidth: number }) {
  const engine = useEditor();
  const scrubbingRef = useRef(false);

  const seekFromEvent = (event: ReactPointerEvent<HTMLDivElement>) => {
    const rect = event.currentTarget.getBoundingClientRect();
    engine.seek(Math.max(0, (event.clientX - rect.left) / pxPerMs));
  };

  const steps = [100, 250, 500, 1000, 2000, 5000, 10_000, 30_000, 60_000, 300_000];
  const stepMs = steps.find((s) => s * pxPerMs >= 70) ?? 300_000;
  const minorMs = stepMs / 5;
  const minorPx = minorMs * pxPerMs;
  const tickCount = Math.ceil(contentWidth / (stepMs * pxPerMs)) + 1;

  return (
    <div
      className="relative cursor-col-resize bg-card"
      style={{
        width: contentWidth,
        height: RULER_HEIGHT,
        backgroundImage: `repeating-linear-gradient(to right, color-mix(in oklab, var(--foreground) 14%, transparent) 0 1px, transparent 1px ${minorPx}px)`,
        backgroundSize: `${minorPx}px 6px`,
        backgroundPosition: "0 100%",
        backgroundRepeat: "repeat-x",
      }}
      onPointerDown={(event) => {
        scrubbingRef.current = true;
        event.currentTarget.setPointerCapture(event.pointerId);
        seekFromEvent(event);
      }}
      onPointerMove={(event) => scrubbingRef.current && seekFromEvent(event)}
      onPointerUp={(event) => {
        scrubbingRef.current = false;
        event.currentTarget.releasePointerCapture(event.pointerId);
      }}
    >
      {Array.from({ length: tickCount }, (_, i) => (
        <div
          key={i}
          className="absolute top-0 h-full border-l border-foreground/15 pl-1 pt-1 font-mono text-2xs leading-none text-muted-foreground select-none"
          style={{ left: i * stepMs * pxPerMs }}
        >
          {formatRulerLabel(i * stepMs)}
        </div>
      ))}
      <RulerMarkers pxPerMs={pxPerMs} />
      <KeywordTicks pxPerMs={pxPerMs} />
    </div>
  );
}

export function Playhead({ pxPerMs, height }: { pxPerMs: number; height: number }) {
  const currentTimeMs = usePlayback((s) => s.currentTimeMs);
  const isPlaying = usePlayback((s) => s.isPlaying);
  const { timelineScrollRef } = useEditorUI();

  // Follow the playhead while playing (manual scrolling stays untouched
  // when paused).
  useEffect(() => {
    if (!isPlaying) return;
    const scroller = timelineScrollRef.current;
    if (!scroller) return;
    const playheadX = HEADER_WIDTH + currentTimeMs * pxPerMs;
    const viewLeft = scroller.scrollLeft + HEADER_WIDTH;
    const viewRight = scroller.scrollLeft + scroller.clientWidth - 40;
    if (playheadX < viewLeft || playheadX > viewRight) {
      scroller.scrollLeft = Math.max(0, playheadX - HEADER_WIDTH - 80);
    }
  }, [currentTimeMs, isPlaying, pxPerMs, timelineScrollRef]);

  return (
    <div
      className="pointer-events-none absolute top-0 z-10 w-px bg-primary"
      style={{ left: HEADER_WIDTH + currentTimeMs * pxPerMs, height }}
    >
      <div className="absolute -top-px -left-[5.5px] flex h-4 w-3 items-start justify-center">
        <div className="h-3 w-3 rounded-[3px] rounded-b-none bg-primary [clip-path:polygon(0_0,100%_0,100%_60%,50%_100%,0_60%)]" />
      </div>
    </div>
  );
}

export function SnapGuide({ pxPerMs, height }: { pxPerMs: number; height: number }) {
  const snapGuideMs = useSnapGuideMs();
  if (snapGuideMs === null) return null;
  return (
    <div
      className="pointer-events-none absolute top-0 z-30 w-px bg-(--snap-guide)"
      style={{ left: HEADER_WIDTH + snapGuideMs * pxPerMs, height }}
    />
  );
}

"use client";

import { useSyncExternalStore } from "react";

/**
 * Persisted transcript keyword terms (e.g. product names), per project.
 * Occurrences highlight in the transcript panel and render as soft ticks on
 * the timeline ruler. Module store + localStorage, the font-library pattern
 * — both panels subscribe without threading props through the shell.
 */

const storageKey = (projectId: string) => `mcut:transcript:keywords:v1:${projectId}`;

const listeners = new Set<() => void>();
const cache = new Map<string, string[]>();
const EMPTY: string[] = [];

function notify(): void {
  for (const listener of listeners) listener();
}

function read(projectId: string): string[] {
  if (typeof window === "undefined") return EMPTY;
  let value = cache.get(projectId);
  if (!value) {
    try {
      const raw = JSON.parse(window.localStorage.getItem(storageKey(projectId)) ?? "[]");
      value = Array.isArray(raw) ? raw.filter((k): k is string => typeof k === "string") : [];
    } catch {
      value = [];
    }
    cache.set(projectId, value);
  }
  return value;
}

export function getTranscriptKeywords(projectId: string): string[] {
  return read(projectId);
}

export function setTranscriptKeywords(projectId: string, keywords: string[]): void {
  const cleaned = [...new Set(keywords.map((k) => k.trim()).filter((k) => k.length > 0))];
  cache.set(projectId, cleaned);
  try {
    window.localStorage.setItem(storageKey(projectId), JSON.stringify(cleaned));
  } catch {
    // Private mode: keywords just don't persist.
  }
  notify();
}

export function addTranscriptKeyword(projectId: string, keyword: string): void {
  setTranscriptKeywords(projectId, [...read(projectId), keyword]);
}

export function removeTranscriptKeyword(projectId: string, keyword: string): void {
  setTranscriptKeywords(
    projectId,
    read(projectId).filter((k) => k !== keyword),
  );
}

function subscribe(onChange: () => void): () => void {
  listeners.add(onChange);
  return () => listeners.delete(onChange);
}

/** Reactive keyword list for a project. */
export function useTranscriptKeywords(projectId: string): string[] {
  return useSyncExternalStore(
    subscribe,
    () => read(projectId),
    () => EMPTY,
  );
}

// ---------------------------------------------------------------------------
// Find-in-transcript event (⌘F): the shell switches to the transcript tab,
// the panel focuses its search box — split so neither imports the other.
// ---------------------------------------------------------------------------

export const TRANSCRIPT_FIND_EVENT = "mcut:transcript-find";

let pendingFocus = false;

export function requestTranscriptFind(): void {
  pendingFocus = true;
  window.dispatchEvent(new Event(TRANSCRIPT_FIND_EVENT));
}

/** The panel calls this on mount to honor a find request that arrived while unmounted. */
export function consumePendingTranscriptFind(): boolean {
  const was = pendingFocus;
  pendingFocus = false;
  return was;
}
